```cpp
#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <map>
#include <set>

using namespace std;

long long get_gcd(long long a, long long b) {
    while (b) {
        a %= b;
        swap(a, b);
    }
    return a;
}

struct Fraction {
    long long n, d;
    Fraction(long long n = 0, long long d = 1) {
        long long g = get_gcd(n, d);
        this->n = n / g;
        this->d = d / g;
    }
    bool operator<(const Fraction& o) const {
        return n * o.d < o.n * d;
    }
    bool operator==(const Fraction& o) const {
        return n == o.n && d == o.d;
    }
};

const int MAX_H = 100000;
long long tree_cnt[400005];
long long tree_sum[400005];

void update(int node, int l, int r, int pos, long long cnt_delta, long long sum_delta) {
    tree_cnt[node] += cnt_delta;
    tree_sum[node] += sum_delta;
    if (l == r) return;
    int mid = l + (r - l) / 2;
    if (pos <= mid) update(2 * node, l, mid, pos, cnt_delta, sum_delta);
    else update(2 * node + 1, mid + 1, r, pos, cnt_delta, sum_delta);
}

long long query(int node, int l, int r, long long k) {
    if (l == r) {
        return k * l;
    }
    int mid = l + (r - l) / 2;
    if (tree_cnt[2 * node] >= k) {
        return query(2 * node, l, mid, k);
    } else {
        return tree_sum[2 * node] + query(2 * node + 1, mid + 1, r, k - tree_cnt[2 * node]);
    }
}

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(NULL);

    int n;
    long long s, k;
    if (!(cin >> n >> s >> k)) return 0;

    vector<long long> h(n), l(n), u(n);
    vector<Fraction> criticals;
    map<Fraction, vector<int>> add_events;
    map<Fraction, vector<int>> rem_events;
    set<Fraction> is_L;

    for (int i = 0; i < n; ++i) {
        cin >> h[i] >> l[i] >> u[i];
        if (k / h[i] >= 1) {
            Fraction L_frac(l[i], h[i]);
            Fraction U_frac(u[i], h[i]);

            criticals.push_back(L_frac);
            criticals.push_back(U_frac);

            add_events[L_frac].push_back(i);
            rem_events[U_frac].push_back(i);
            is_L.insert(L_frac);
        }
    }

    sort(criticals.begin(), criticals.end());
    criticals.erase(unique(criticals.begin(), criticals.end()), criticals.end());

    Fraction best_cost(-1, 1);
    bool possible = false;

    for (const auto& F : criticals) {
        for (int i : add_events[F]) {
            long long m = k / h[i];
            update(1, 1, MAX_H, h[i], m, m * h[i]);
        }

        if (is_L.count(F)) {
            if (tree_cnt[1] >= s) {
                long long cur_sum = query(1, 1, MAX_H, s);
                Fraction cur_cost(F.n * cur_sum, F.d);
                if (!possible || cur_cost < best_cost) {
                    best_cost = cur_cost;
                    possible = true;
                }
            }
        }

        for (int i : rem_events[F]) {
            long long m = k / h[i];
            update(1, 1, MAX_H, h[i], -m, -(m * h[i]));
        }
    }

    if (possible) {
        cout << best_cost.n << " " << best_cost.d << "\n";
    } else {
        cout << "*\n";
    }

    return 0;
}

