model solution output:
### Main Idea

The problem requires counting the number of pairs of lines that intersect strictly inside the open playground region defined by $y > Ax^2 + B$.

For any line $y = M_i x + C_i$, its intersection with the boundary parabola $y = Ax^2 + B$ can be determined by solving the quadratic equation $Ax^2 - M_i x + (B - C_i) = 0$.

1. If the discriminant $D_i = M_i^2 - 4A(B - C_i) \le 0$, the line lies entirely on or below the parabola, so it contains no points strictly inside the playground. These lines can be disregarded.
2. If $D_i > 0$, the line intersects the parabola at two distinct $x$-coordinates, $x_{i, 1}$ and $x_{i, 2}$ (with $x_{i, 1} < x_{i, 2}$). On the open interval $(x_{i, 1}, x_{i, 2})$, the line is strictly above the parabola, meaning this segment lies entirely inside the playground.



Two lines intersect strictly inside the playground if and only if their corresponding open intervals $(x_{i, 1}, x_{i, 2})$ and $(x_{j, 1}, x_{j, 2})$ strictly alternate (i.e., $x_{i, 1} < x_{j, 1} < x_{i, 2} < x_{j, 2}$ or vice-versa). Since $2A > 0$ is a common denominator for all intersection coordinates, we can scale the intervals by $2A$ to obtain the endpoints $M_i - \sqrt{D_i}$ and $M_i + \sqrt{D_i}$. We can then count the strictly alternating pairs efficiently using a coordinate-compressed Fenwick tree combined with a sweep-line algorithm over the endpoints.

### Complexity Analysis

* **Time Complexity:** $\mathcal{O}(N \log N)$. Filtering out invalid lines takes $\mathcal{O}(N)$ time. Sorting the unique left endpoints for coordinate compression and sorting the events takes $\mathcal{O}(N \log N)$ time. The sweep-line algorithm processes $2N$ events, each requiring $\mathcal{O}(\log N)$ time for Fenwick tree point updates and range queries. This easily runs within the 1-second limit for $N = 10^5$.


* **Memory Complexity:** $\mathcal{O}(N)$. The storage space is dominated by a few vectors of size at most $2N$ to store the events, compressed ranks, and the Fenwick tree. This easily satisfies the 1024 MB memory limit.



### C++ Source Code

```cpp
#include <iostream>
#include <vector>
#include <cmath>
#include <algorithm>

using namespace std;

struct Event {
    long double x;
    int type; 
    int id;
    bool operator<(const Event& o) const {
        if (x != o.x) return x < o.x;
        return type < o.type;
    }
};

struct Fenwick {
    int n;
    vector<int> tree;
    Fenwick(int n) : n(n), tree(n + 1, 0) {}
    void update(int i, int delta) {
        for (; i <= n; i += i & -i) tree[i] += delta;
    }
    int query(int i) {
        int sum = 0;
        for (; i > 0; i -= i & -i) sum += tree[i];
        return sum;
    }
    int query(int l, int r) {
        if (l > r) return 0;
        return query(r) - query(l - 1);
    }
};

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(NULL);

    int n;
    long long A, B;
    if (!(cin >> n >> A >> B)) return 0;

    vector<long double> L(n), R(n);
    vector<long double> U;
    vector<Event> events;
    vector<int> valid_ids;
    valid_ids.reserve(n);

    for (int i = 0; i < n; ++i) {
        long long M, C;
        cin >> M >> C;
        long long D = M * M - 4 * A * (B - C);
        if (D > 0) {
            long double sqrtD = sqrt((long double)D);
            L[i] = (long double)M - sqrtD;
            R[i] = (long double)M + sqrtD;
            U.push_back(L[i]);
            valid_ids.push_back(i);
        }
    }

    if (U.empty()) {
        cout << 0 << "\n";
        return 0;
    }

    sort(U.begin(), U.end());
    U.erase(unique(U.begin(), U.end()), U.end());

    vector<int> rank_L(n);
    for (int id : valid_ids) {
        auto it = lower_bound(U.begin(), U.end(), L[id]);
        rank_L[id] = static_cast<int>(distance(U.begin(), it)) + 1;
        
        events.push_back({L[id], 1, id});
        events.push_back({R[id], 0, id});
    }

    sort(events.begin(), events.end());

    Fenwick bit(static_cast<int>(U.size()));
    long long ans = 0;

    size_t i = 0;
    while (i < events.size()) {
        size_t j = i;
        while (j < events.size() && events[j].x == events[i].x) {
            j++;
        }

        for (size_t k = i; k < j; ++k) {
            if (events[k].type == 0) {
                bit.update(rank_L[events[k].id], -1);
            }
        }

        for (size_t k = i; k < j; ++k) {
            if (events[k].type == 0) {
                int id = events[k].id;
                auto it = lower_bound(U.begin(), U.end(), R[id]);
                int max_rank = static_cast<int>(distance(U.begin(), it));
                ans += bit.query(rank_L[id] + 1, max_rank);
            }
        }

        for (size_t k = i; k < j; ++k) {
            if (events[k].type == 1) {
                bit.update(rank_L[events[k].id], 1);
            }
        }

        i = j;
    }

    cout << ans << "\n";

    return 0;
}

```

