int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(NULL);

    int N;
    long long A, B;
    if (!(cin >> N >> A >> B)) return 0;

    vector<pair<long double, long double>> intervals;
    vector<long double> coords;

    for (int i = 0; i < N; ++i) {
        long long M, C;
        cin >> M >> C;
        long long D = M * M - 4LL * A * (B - C);
        if (D > 0) {
            long double sqrt_D = sqrtl(D);
            long double L = (M - sqrt_D) / (2.0L * A);
            long double R = (M + sqrt_D) / (2.0L * A);
            intervals.push_back({L, R});
            coords.push_back(L);
            coords.push_back(R);
        }
    }

    sort(coords.begin(), coords.end());
    coords.erase(unique(coords.begin(), coords.end()), coords.end());

    vector<pair<int, int>> rank_intervals;
    rank_intervals.reserve(intervals.size());
    for (const auto& p : intervals) {
        int rL = lower_bound(coords.begin(), coords.end(), p.first) - coords.begin() + 1;
        int rR = lower_bound(coords.begin(), coords.end(), p.second) - coords.begin() + 1;
        rank_intervals.push_back({rL, rR});
    }

    sort(rank_intervals.begin(), rank_intervals.end());

    long long ans = 0;
    int K = coords.size();
    Fenwick bit(K);

    int n_int = rank_intervals.size();
    for (int i = 0; i < n_int; ) {
        int j = i;
        while (j < n_int && rank_intervals[j].first == rank_intervals[i].first) {
            j++;
