model solution output:
### Main idea

The problem asks us to find a valid path from floor $1$ to floor $2N$ using directed edges (where $S < T$), such that no two visited floors belong to the same sensor pair $\{i, i+N\}$.
Because any edge from the left half $L = \{1 \dots N\}$ to the right half $R = \{N+1 \dots 2N\}$ goes strictly forward and we can never return to $L$, any valid path consists of three parts:

1. A path $P_L$ entirely within $L$, starting at $1$ and ending at some node $u$.
2. A single "bridge" edge from $u \in L$ to $v+N \in R$.
3. A path $P_R'$ entirely within $R$, starting at $v+N$ and ending at $2N$.

If we map $P_R'$ back to $L$ by subtracting $N$ from each floor, we get a path $P_R$ in $L$ that starts at $v$ and ends at $N$. The sensor condition explicitly requires that $P_L$ and $P_R$ share **no common vertices**.
Thus, the problem reduces to finding a valid bridge edge $u \to v+N$ and two strictly disjoint paths in $L$: one from $1$ to $u$, and one from $v$ to $N$. We can solve this by building both paths simultaneously from left to right.

### Technique used

Dynamic Programming on a Directed Acyclic Graph (DAG) with Bitsets, followed by Breadth-First Search (BFS) for path reconstruction.

### Correctness argument

To find two disjoint paths, we maintain two pointers: $x$ (the end of $P_L$) and $y$ (the end of $P_R$). We always advance the strictly smaller pointer. Because edges only point to strictly larger vertices, advancing the smaller pointer ensures that if the two paths were ever to intersect, they would be forced into a state where $x = y$. By explicitly forbidding any transition that results in $x = y$, we mathematically guarantee that $P_L$ and $P_R$ remain entirely disjoint.

The paths are built in two phases:

* **Phase 1 (Active):** Both paths are being built. We advance the smaller of $x$ and $y$.
* **Phase 2 (Frozen):** $P_L$ has reached its final destination $u$. We "freeze" $x$ at $u$ (only permitted if $x < y$) and then exclusively advance $y$ until it reaches $N$.

Since there are up to $N$ possible starting points $v$ for $P_R$, we compute reachability for all $v$ simultaneously using `std::bitset`. Once a valid bridge edge is confirmed to have reachable disjoint paths, we run a single deterministic BFS to reconstruct the exact path.

### Complexity analysis

* **Time Complexity:** The dynamic programming processes $O(N^2)$ states. From each state, transitions iterate over outbound edges, bounded by $M$. Operations on the bitset take $O(N / 64)$ time. This gives a time complexity of $\mathcal{O}(N^2 + \frac{N \cdot M}{64})$ for the DP phase. The BFS visits at most $O(N^2)$ states and takes $\mathcal{O}(N \cdot M)$ time. Overall Time Complexity is $\mathcal{O}(N \cdot M)$, well within the 1-second limit.
* **Memory Complexity:** The `std::bitset` arrays require $2 \times 505 \times 505 \times \frac{505}{8}$ bytes $\approx 32 \text{ MB}$. The BFS tracking structures require $\approx 6 \text{ MB}$. Overall Space Complexity is $\mathcal{O}(N^3 / 64 + N^2)$, easily satisfying the 1024 MB limit.

### Complete C++20 implementation

```cpp
#include <iostream>
#include <vector>
#include <bitset>
#include <queue>
#include <algorithm>

using namespace std;

static bitset<505> dp[505][505];
static bitset<505> dp_frozen[505][505];

struct State {
    int x, y, f;
};

static bool vis[505][505][2];
static State parent_state[505][505][2];

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(NULL);

    int N, M;
    if (!(cin >> N >> M)) return 0;

    vector<vector<int>> adj_orig(2 * N + 1);
    vector<vector<int>> GL(N + 1);
    vector<vector<int>> GR(N + 1);

    for (int i = 0; i < M; ++i) {
        int u, v;
        cin >> u >> v;
        adj_orig[u].push_back(v);
        if (u <= N && v <= N) GL[u].push_back(v);
        if (u > N && v > N) GR[u - N].push_back(v - N);
    }

    for (int v = 2; v <= N; ++v) {
        dp[1][v].set(v);
    }

    for (int S = 3; S <= 2 * N; ++S) {
        for (int x = 1; x < S && x <= N; ++x) {
            int y = S - x;
            if (y > N || x == y) continue;

            if (x < y) {
                dp_frozen[x][y] |= dp[x][y];
            }

            if (dp[x][y].any()) {
                if (x < y) {
                    for (int nxt : GL[x]) {
                        if (nxt != y) {
                            dp[nxt][y] |= dp[x][y];
                        }
                    }
                } else {
                    for (int nxt : GR[y]) {
                        if (nxt != x) {
                            dp[x][nxt] |= dp[x][y];
                        }
                    }
                }
            }

            if (dp_frozen[x][y].any()) {
                for (int nxt : GR[y]) {
                    dp_frozen[x][nxt] |= dp_frozen[x][y];
                }
            }
        }
    }

    int best_u = -1, best_v = -1;
    for (int u = 1; u < N; ++u) {
        for (int target : adj_orig[u]) {
            if (target > N) {
                int v = target - N;
                if (dp_frozen[u][N].test(v)) {
                    best_u = u;
                    best_v = v;
                    break;
                }
            }
        }
        if (best_u != -1) break;
    }

    if (best_u == -1) {
        cout << "*\n";
        return 0;
    }

    queue<State> q;
    q.push({1, best_v, 0});
    vis[1][best_v][0] = true;

    while (!q.empty()) {
        auto [x, y, f] = q.front();
        q.pop();

        if (x == best_u && y == N && f == 1) break;

        if (f == 0) {
            if (x < y && !vis[x][y][1]) {
                vis[x][y][1] = true;
                parent_state[x][y][1] = {x, y, 0};
                q.push({x, y, 1});
            }

            if (x < y) {
                for (int nxt : GL[x]) {
                    if (nxt != y && !vis[nxt][y][0]) {
                        vis[nxt][y][0] = true;
                        parent_state[nxt][y][0] = {x, y, 0};
                        q.push({nxt, y, 0});
                    }
                }
            } else {
                for (int nxt : GR[y]) {
                    if (nxt != x && !vis[x][nxt][0]) {
                        vis[x][nxt][0] = true;
                        parent_state[x][nxt][0] = {x, y, 0};
                        q.push({x, nxt, 0});
                    }
                }
            }
        } else {
            for (int nxt : GR[y]) {
                if (!vis[x][nxt][1]) {
                    vis[x][nxt][1] = true;
                    parent_state[x][nxt][1] = {x, y, 1};
                    q.push({x, nxt, 1});
                }
            }
        }
    }

    vector<int> pathL, pathR;
