model solution output:
### Main idea

The number of digits to exact decimal representation of $\frac{A_i}{A_j}$ is exactly the sum of the digits required for its integer part and its fractional part. Since the decimal point itself does not count as a digit, we can treat the two parts separately.

1. **Integer Part**: The number of digits of $\lfloor A_i/A_j \rfloor$ is $1$ if the quotient is zero, and $\lfloor \log_{10}(A_i/A_j) \rfloor + 1$ otherwise. By iterating through all possible values of $A_j \in [1, 10^5]$, we can determine the range of $A_i$ that yields 1, 2, 3, ... digits. Using a frequency prefix-sum array, we can find the exact number of elements in each range in $O(1)$ time for each interval.
2. **Fractional Part**: Let $v = \frac{A_j}{\gcd(A_i, A_j)}$. When written as $v = 2^a \cdot 5^b \cdot k$ (where $\gcd(k, 10) = 1$), the fractional part has a pre-period of length $\max(a, b)$ and a period of length equal to the multiplicative order of $10$ modulo $k$. Let this total length be $C(v) = \max(a, b) + \text{ord}_k(10)$.
To efficiently compute the sum over all pairs, we can rewrite $v = \frac{A_j}{\gcd(A_i, A_j)}$ using Möbius inversion. The number of elements $A_i$ producing a specific denominator $v$ for a given $A_j$ corresponds to the count of $A_i$ such that $A_i = c \cdot \frac{A_j}{v}$ and $\gcd(c, v) = 1$. This can be efficiently computed by factoring the problem into multiples and square-free divisors using the Möbius function $\mu$.

### Technique used

* Number Theory (Multiplicative Order, Möbius Inversion, Sieve)
* Prefix Sums / Frequency Arrays

### Correctness argument

By properties of decimals, any fraction in its lowest terms $\frac{u}{v}$ has a decimal expansion where the terminating (pre-period) length is $\max(v_2, v_5)$ and the repeating (period) length is the minimum $p > 0$ such that $10^p \equiv 1 \pmod k$, where $k$ is $v$ stripped of factors of 2 and 5. This evaluates $C(v)$ correctly. Applying the Möbius function allows translating the coprimality condition into a sum over divisors, reducing a double loop evaluating $\gcd$ to counting multiples of numbers. The prefix sums logic correctly bins the integer digits bounded strictly by powers of 10.

### Complexity analysis

* **Time Complexity:** $O(M \log^2 M + N)$, where $M = \max(A_i) \le 10^5$. Factoring $\phi(k)$, calculating powers, generating prefix sums of frequencies, and traversing divisors take $O(M \log M)$ overall. The nested divisor traversals during Möbius sum evaluation run in essentially bounded limits close to $O(M \log^2 M)$.
* **Space/Memory Complexity:** $O(M \log M)$ auxiliary memory for sieves, sequences of divisors, multiplicative properties, and counts. This easily scales to only a few megabytes, strictly abiding by the 1024 MB restriction.

### Complete C++20 implementation

```cpp
#include <iostream>
#include <vector>
#include <algorithm>

using namespace std;

const int MOD = 998244353;

long long power(long long base, long long exp, long long mod) {
    long long res = 1;
    base %= mod;
    while (exp > 0) {
        if (exp % 2 == 1) res = (res * base) % mod;
        base = (base * base) % mod;
        exp /= 2;
    }
    return res;
}

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(NULL);

    int n;
    if (!(cin >> n)) return 0;

    int max_val = 0;
    vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        cin >> a[i];
        if (a[i] > max_val) {
            max_val = a[i];
        }
    }

    int M = max_val;
    vector<int> cnt(M + 1, 0);
    for (int i = 0; i < n; ++i) {
        cnt[a[i]]++;
    }

    vector<int> pref(M + 1, 0);
    for (int i = 1; i <= M; ++i) {
        pref[i] = pref[i - 1] + cnt[i];
    }

    vector<int> F(M + 1, 0);
    for (int i = 1; i <= M; ++i) {
        for (int j = i; j <= M; j += i) {
            F[i] += cnt[j];
        }
    }

    vector<int> primes;
    vector<int> min_prime(M + 1, 0);
    vector<int> phi(M + 1, 0);
    vector<int> mu(M + 1, 0);

    phi[1] = 1;
    mu[1] = 1;
    for (int i = 2; i <= M; ++i) {
        if (min_prime[i] == 0) {
            min_prime[i] = i;
            primes.push_back(i);
            phi[i] = i - 1;
            mu[i] = -1;
        }
        for (int p : primes) {
            if (p * i > M) break;
            min_prime[p * i] = p;
            if (i % p == 0) {
                phi[p * i] = phi[i] * p;
                mu[p * i] = 0;
                break;
            } else {
                phi[p * i] = phi[i] * (p - 1);
                mu[p * i] = -mu[i];
            }
        }
    }

    vector<vector<int>> pf(M + 1);
    for (int i = 2; i <= M; ++i) {
        if (min_prime[i] == i) {
            for (int j = i; j <= M; j += i) {
                pf[j].push_back(i);
            }
        }
    }

    vector<int> ord(M + 1, 0);
    for (int k = 1; k <= M; ++k) {
        if (k % 2 == 0 || k % 5 == 0) continue;
        if (k == 1) {
            ord[k] = 0;
            continue;
        }
        int o = phi[k];
        for (int p : pf[phi[k]]) {
            while (o % p == 0) {
                if (power(10, o / p, k) == 1) {
                    o /= p;
                } else {
                    break;
                }
            }
        }
        ord[k] = o;
    }

    vector<int> C(M + 1, 0);
    for (int v = 1; v <= M; ++v) {
        int temp = v;
        int a_pow = 0, b_pow = 0;
        while (temp % 2 == 0) { a_pow++; temp /= 2; }
        while (temp % 5 == 0) { b_pow++; temp /= 5; }
        int k = temp;
        C[v] = max(a_pow, b_pow) + ord[k];
    }

    vector<vector<int>> sq_divs(M + 1);
    for (int m = 1; m <= M; ++m) {
        if (mu[m] != 0) {
            for (int v = m; v <= M; v += m) {
                sq_divs[v].push_back(m);
            }
        }
    }

    long long total_part1 = 0;
    for (int Y = 1; Y <= M; ++Y) {
        if (cnt[Y] == 0) continue;
        long long sum_Y = 0;

        long long L = 1;
        long long R = min((long long)M, Y * 10LL - 1);
        if (L <= R) {
            sum_Y += (pref[R] - pref[L - 1]) * 1;
        }

        long long p10 = 10;
        for (int digits = 2; digits <= 6; ++digits) {
            L = Y * p10;
            if (L > M) break;
            R = min((long long)M, Y * p10 * 10 - 1);
            if (L <= R) {
                sum_Y += (pref[R] - pref[L - 1]) * digits;
            }
            p10 *= 10;
        }
        total_part1 = (total_part1 + (sum_Y % MOD) * cnt[Y]) % MOD;
    }

    long long total_part2 = 0;
    for (int v = 1; v <= M; ++v) {
        if (C[v] == 0) continue;
        for (int d = 1; d * v <= M; ++d) {
            if (cnt[d * v] == 0) continue;
            long long g_dv = 0;
            for (int m : sq_divs[v]) {
                if (mu[m] == 1) {
                    g_dv += F[d * m];
                } else if (mu[m] == -1) {
                    g_dv -= F[d * m];
                }
            }
            g_dv %= MOD;
            if (g_dv < 0) g_dv += MOD;
            total_part2 = (total_part2 + 1LL * cnt[d * v] * C[v] % MOD * g_dv) % MOD;
        }
    }

    long long total_sum = (total_part1 + total_part2) % MOD;
    long long Q = (1LL * n * n) % MOD;
    long long Q_inv = power(Q, MOD - 2, MOD);
    long long ans = (total_sum * Q_inv) % MOD;

    cout << ans << "\n";

    return 0;
}

