        for (int l_bit = 0; l_bit <= 1; ++l_bit) {
            int nw_greater = w_greater;
            if (w_bit > x_bit) nw_greater = 1;
            else if (w_bit < x_bit) nw_greater = 0;

            int nl_greater = l_greater;
            if (l_bit > y_bit) nl_greater = 1;
            else if (l_bit < y_bit) nl_greater = 0;

            int c_out = (w_bit + l_bit + carry_in) / 2;
            long long contrib = (1LL << bit) * (w_bit + l_bit) - c_out;

            long long nxt = solve(bit + 1, nw_greater, nl_greater, c_out, X, Y);
            if (nxt != MIN_INF) {
                ans = max(ans, contrib + nxt);
            }
        }
    }

    return memo[bit][w_greater][l_greater][carry_in] = ans;
}

long long power(long long base, long long exp) {
    long long res = 1;
    base %= 1000000007;
    while (exp > 0) {
        if (exp % 2 == 1) res = (res * base) % 1000000007;
        base = (base * base) % 1000000007;
        exp /= 2;
    }
    return res;
}

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(NULL);
    
    long long A, B;
    if (cin >> A >> B) {
        long long X = A - 1;
        long long Y = B - 1;
        
        for (int i = 0; i < 63; ++i) {
            for (int j = 0; j < 2; ++j) {
                for (int k = 0; k < 2; ++k) {
                    for (int l = 0; l < 2; ++l) {
                        memo[i][j][k][l] = -1;
                    }
                }
            }
        }
        
        long long max_val = solve(0, 0, 0, 0, X, Y);
        long long K = max_val + 1;
        
        cout << power(2, K) << "\n";
    }
    
    return 0;
}

