model solution output:
## Main idea

The problem asks whether a given graph $G$ can be the "square" of a tree $T$, meaning that an edge exists in $G$ if and only if the distance between the two vertices in $T$ is 1 or 2.

The square of any tree is a chordal graph. For a chordal graph, we can find all its maximal cliques in linear time using a Maximum Cardinality Search (MCS) to generate a Perfect Elimination Ordering (PEO). According to the Ross-Harary theorem, if $G$ is not a complete graph, its maximal cliques correspond exactly to the closed neighborhoods of the internal vertices of $T$.

We can count the number of cliques each vertex belongs to. Vertices belonging to only one clique are leaves in $T$, while vertices belonging to multiple cliques are internal vertices. This gives a one-to-one correspondence between the maximal cliques and the internal vertices. We can then construct a bipartite graph to uniquely match each clique to its true center vertex (the corresponding internal vertex). After identifying the center of each clique, we can reconstruct the edges of $T$ and verify if the reconstructed tree's square matches $G$ perfectly.

## Technique used

* Graph Algorithms (Chordal Graphs, Maximum Cardinality Search, Perfect Elimination Ordering)
* Bipartite Matching (Kuhn's Algorithm)
* Tree Properties and Verification

## Correctness argument

1. **Chordal Graph & PEO:** An MCS ordering gives a valid PEO if and only if the graph is chordal. From the PEO, we can identify all maximal cliques by checking filtering conditions based on higher-indexed neighborhoods.
2. **Cliques to Internal Vertices:** In a tree square graph, the closed neighborhood of any internal vertex $v$ forms a maximal clique. Leaves only belong to the clique centered at their parent, whereas internal vertices belong to multiple cliques. Thus, the number of cliques matches the number of internal vertices.
3. **Center Identification:** For any clique $C$, its true center $v$ is the only vertex whose neighborhood completely covers the remaining branch connections of the adjacent cliques. We formalize this by checking if any outside neighbor of a candidate center is uniquely connected to it within the clique's internal vertices.
4. **Final Verification:** Verification ensures that $T$ is a valid connected tree, the total number of distance-2 pairs matches the edge count $M$, and every distance-2 pair exists in $G$. Due to the exact matching of edge count and subset containment, $T^2 = G$ is guaranteed.

## Complexity analysis

* **Time Complexity:** - MCS and PEO generation: $O(N + M)$ using bucket queues.
* Clique filtering and classification: $O(N + M)$.
* Bipartite matching: $O(K)$ where $K \le N$ is the number of internal vertices since degrees in the matching graph are bounded by 2 for the ambiguous paths.
* Verification: $O(M \log N)$ to check all distance $\le 2$ pairs via binary search on the adjacency lists.
* Overall Time Complexity: $O(M \log N)$, which runs well within the 1.5-second limit.


* **Memory Complexity:** $O(N + M)$ to store the graph, cliques, buckets, and matching pairs, which uses a small fraction of the 1024 MB limit.

## Complete C++14 implementation

```cpp
#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

using namespace std;

bool is_center(int x, const vector<int>& I_C, const vector<vector<int>>& adj, const vector<bool>& in_C) {
    for (int w : adj[x]) {
        if (!in_C[w]) {
            bool shared = false;
            for (int y : I_C) {
                if (y != x && binary_search(adj[y].begin(), adj[y].end(), w)) {
                    shared = true;
                    break;
                }
            }
            if (!shared) return false;
        }
    }
    return true;
}

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(NULL);

    int n, m;
    if (!(cin >> n >> m)) return 0;

    vector<vector<int>> adj(n + 1);
    for (int i = 0; i < m; ++i) {
        int u, v;
        cin >> u >> v;
        adj[u].push_back(v);
        adj[v].push_back(u);
    }

    for (int i = 1; i <= n; ++i) {
        sort(adj[i].begin(), adj[i].end());
    }

    vector<int> peo; peo.reserve(n);
    vector<int> pos(n + 1, 0);
    vector<int> label_count(n + 1, 0);
    vector<vector<int>> buckets(n + 1);
    for (int i = 1; i <= n; ++i) buckets[0].push_back(i);
    vector<bool> vis_peo(n + 1, false);
    int max_bucket = 0;

    for (int step = 0; step < n; ++step) {
        while (max_bucket >= 0 && buckets[max_bucket].empty()) {
            max_bucket--;
        }
        if (max_bucket < 0) break;
        int u = buckets[max_bucket].back();
        buckets[max_bucket].pop_back();
        if (vis_peo[u]) { step--; continue; }
        vis_peo[u] = true;
        peo.push_back(u);
        pos[u] = peo.size();

        for (int v : adj[u]) {
            if (!vis_peo[v]) {
                label_count[v]++;
                buckets[label_count[v]].push_back(v);
                max_bucket = max(max_bucket, label_count[v]);
            }
        }
    }

    vector<vector<int>> cliques;
    vector<int> X_size(n + 1, 0);
    vector<int> first_higher(n + 1, 0);
    vector<bool> marked(n + 1, false);

    vector<vector<int>> X(n + 1);
    for (int i = 0; i < n; ++i) {
        int u = peo[i];
        for (int v : adj[u]) {
            if (pos[v] > pos[u]) {
                X[u].push_back(v);
            }
        }
        sort(X[u].begin(), X[u].end(), [&](int a, int b){
            return pos[a] < pos[b];
        });
        X_size[u] = X[u].size();
        if (!X[u].empty()) {
            first_higher[u] = X[u][0];
        }
    }

    for (int i = 0; i < n; ++i) {
        int u = peo[i];
        if (!X[u].empty()) {
            int v = first_higher[u];
            if (X_size[u] - 1 == X_size[v]) {
                marked[v] = true;
            }
        }
    }

    for (int i = 0; i < n; ++i) {
        int u = peo[i];
        if (!marked[u]) {
            vector<int> C = X[u];
            C.push_back(u);
            cliques.push_back(C);
        }
    }

    if (cliques.empty()) {
        cout << "*\n";
        return 0;
    }

    if (cliques.size() == 1) {
        if (cliques[0].size() == n && m == (long long)n * (n - 1) / 2) {
            for (int i = 2; i <= n; ++i) {
                cout << 1 << " " << i << "\n";
            }
        } else {
            cout << "*\n";
        }
        return 0;
    }

    int k = cliques.size();
    vector<int> clique_count(n + 1, 0);
    for (int i = 0; i < k; ++i) {
        for (int v : cliques[i]) {
            clique_count[v]++;
        }
    }

    vector<vector<int>> I(k);
    for (int i = 0; i < k; ++i) {
        for (int v : cliques[i]) {
            if (clique_count[v] >= 2) {
                I[i].push_back(v);
            }
        }
    }

    vector<int> internal_nodes;
    for (int i = 1; i <= n; ++i) {
        if (clique_count[i] >= 2) {
            internal_nodes.push_back(i);
        }
    }

    if ((int)internal_nodes.size() != k) {
        cout << "*\n";
        return 0;
    }

    vector<int> inv_internal(n + 1, -1);
    for (int i = 0; i < k; ++i) {
        inv_internal[internal_nodes[i]] = i;
    }

    vector<vector<int>> match_adj(k);
    vector<bool> in_C(n + 1, false);

    for (int i = 0; i < k; ++i) {
        if (I[i].size() == 1) {
            int v = I[i][0];
            match_adj[i].push_back(inv_internal[v]);
        } else if (I[i].size() == 2) {
            for (int v : cliques[i]) in_C[v] = true;
            for (int v : I[i]) {
                if (is_center(v, I[i], adj, in_C)) {
                    match_adj[i].push_back(inv_internal[v]);
                }
            }
            for (int v : cliques[i]) in_C[v] = false;
        } else {
            for (int v : I[i]) {
                if (clique_count[v] == (int)I[i].size()) {
                    match_adj[i].push_back(inv_internal[v]);
                }
            }
        }
    }

    vector<int> match_left(k, -1), match_right(k, -1);
    vector<bool> vis_match(k, false);

    auto dfs_match = [&](auto& self, int u) -> bool {
        for (int v : match_adj[u]) {
            if (!vis_match[v]) {
                vis_match[v] = true;
                if (match_right[v] < 0 || self(self, match_right[v])) {
                    match_left[u] = v;
                    match_right[v] = u;
                    return true;
                }
            }
        }
        return false;
    };

    int match_count = 0;
    for (int i = 0; i < k; ++i) {
        fill(vis_match.begin(), vis_match.end(), false);
        if (dfs_match(dfs_match, i)) {
            match_count++;
        }
    }

    if (match_count < k) {
        cout << "*\n";
        return 0;
    }

    vector<pair<int, int>> tree_edges;
    for (int i = 0; i < k; ++i) {
        int u = internal_nodes[match_left[i]];
        for (int v : cliques[i]) {
            if (v != u) {
                tree_edges.push_back({min(u, v), max(u, v)});
            }
        }
    }

    sort(tree_edges.begin(), tree_edges.end());
    tree_edges.erase(unique(tree_edges.begin(), tree_edges.end()), tree_edges.end());

    if ((int)tree_edges.size() != n - 1) {
        cout << "*\n";
        return 0;
    }

    vector<vector<int>> T_adj(n + 1);
    vector<int> parent_dsu(n + 1);
    iota(parent_dsu.begin(), parent_dsu.end(), 0);

    auto find_dsu = [&](auto& self, int i) -> int {
        return parent_dsu[i] == i ? i : parent_dsu[i] = self(self, parent_dsu[i]);
    };

    int components = n;
    for (auto& edge : tree_edges) {
        T_adj[edge.first].push_back(edge.second);
        T_adj[edge.second].push_back(edge.first);
        int root1 = find_dsu(find_dsu, edge.first);
        int root2 = find_dsu(find_dsu, edge.second);
        if (root1 != root2) {
            parent_dsu[root1] = root2;
            components--;
        }
    }

    if (components != 1) {
        cout << "*\n";
        return 0;
    }

    long long total_edges = n - 1;
    for (int i = 1; i <= n; ++i) {
        long long d = T_adj[i].size();
        total_edges += d * (d - 1) / 2;
    }

    if (total_edges != m) {
        cout << "*\n";
        return 0;
    }

    for (int u = 1; u <= n; ++u) {
        for (int v : T_adj[u]) {
            if (u < v) {
                if (!binary_search(adj[u].begin(), adj[u].end(), v)) {
                    cout << "*\n";
                    return 0;
                }
            }
            for (int w : T_adj[v]) {
                if (w != u && u < w) {
                    if (!binary_search(adj[u].begin(), adj[u].end(), w)) {
                        cout << "*\n";
                        return 0;
                    }
                }
            }
        }
    }

    for (auto& edge : tree_edges) {
        cout << edge.first << " " << edge.second << "\n";
    }

    return 0;
}

