model solution output:
### Main idea

The problem asks for the weighted sum of query results across a sequence of updates. Since the function calls form a static Directed Acyclic Graph (DAG), the total execution time for a function $u$ can be expressed as $T(u) = \sum_v P(u, v) B_v$, where $P(u, v)$ is the number of directed paths from $u$ to $v$.

Instead of updating forward, we can calculate the contribution of each base time update offline by processing events in reverse. If an update changes $B_v$ by $\Delta$ at time $t$, this adds $\Delta \times \sum_{k > t} k \cdot P(i_k, v)$ to the final answer. To evaluate these sums efficiently without an $\mathcal{O}(N)$ penalty per event, we process the events backward in blocks.

### Technique used

* **Offline Processing & Time Reversal**: To accumulate the effect of $\Delta$ changes over future queries.
* **Square Root Decomposition (Block Processing)**: To batch query propagations and minimize DAG traversals.
* **Dynamic Programming on DAG**: To precalculate path counts between all node pairs.

### Correctness argument

By linearity of summation, the overall answer is the sum over all nodes $v$ of its base value $B_v$ multiplied by the weighted queries reaching $v$. Because $B_v$ is piecewise constant, an update modifying it by $\Delta$ strictly influences all queries occurring *after* it.

Traversing events backward in blocks of size $S$:

1. For updates inside a block, the required sum of future queries is formed by the exact sums from fully processed subsequent blocks (maintained in an array $W$) plus the specific queries encountered so far within the current block (calculated directly using the precomputed $P(u, v)$).
2. After completing a block, its queries are added to a `Lazy` array and pushed down the DAG in topological order. This ensures $W$ is strictly maintained in $\mathcal{O}(N+M)$ time per block, ensuring exact telescoping without double-counting.

### Complexity analysis

* **Time Complexity:** Precomputing $P(u, v)$ takes $\mathcal{O}(M \cdot N)$ via DP in reverse topological order. Processing $E$ events in blocks of size $S$ takes $\mathcal{O}(E \cdot S)$ intra-block operations and $\mathcal{O}(\frac{E}{S}(N+M))$ for pushing lazy evaluations. With $S \approx \sqrt{N+M} \approx 250$, the overall time complexity is $\mathcal{O}(M \cdot N + E \sqrt{N+M})$, easily executing within the generous 5.5-second time limit.
* **Space/Memory Complexity:** $\mathcal{O}(N^2)$ for the matrix $P$ requires around $\approx 256 \text{ MB}$, and $\mathcal{O}(N+M+E)$ handles the graph lists and events. This fits optimally within the 1024 MB memory limit.

### Complete C++20 implementation

```cpp
#pragma GCC optimize("O3,unroll-loops")
#pragma GCC target("avx2,bmi,bmi2,lzcnt,popcnt")

#include <iostream>
#include <vector>
#include <queue>
#include <algorithm>

using namespace std;

const int MOD = 1e9 + 7;
static int P[8005][8005];
vector<int> adj[8005];
int B[8005];
int B_init[8005];

struct Event {
    int type; 
    int u;
    int val;
    long long delta;
    int k;
};

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(NULL);

    int N;
    if (!(cin >> N)) return 0;

    for (int i = 1; i <= N; ++i) {
        cin >> B[i];
        B_init[i] = B[i];
    }

    int M;
    cin >> M;
    vector<int> in_degree(N + 1, 0);
    for (int i = 0; i < M; ++i) {
        int u, v;
        cin >> u >> v;
        adj[u].push_back(v);
        in_degree[v]++;
    }

    vector<int> topo;
    topo.reserve(N);
    queue<int> q;
    for (int i = 1; i <= N; ++i) {
        if (in_degree[i] == 0) q.push(i);
    }

    while (!q.empty()) {
        int u = q.front();
        q.pop();
        topo.push_back(u);
        for (int v : adj[u]) {
            if (--in_degree[v] == 0) q.push(v);
        }
    }

    for (int i = N - 1; i >= 0; --i) {
        int u = topo[i];
        P[u][u] = 1;
        for (int v : adj[u]) {
            for (int w = 1; w <= N; ++w) {
                P[u][w] += P[v][w];
                if (P[u][w] >= MOD) P[u][w] -= MOD;
            }
        }
    }

    int E;
    cin >> E;
    vector<Event> events(E);
    int q_cnt = 0;

    for (int i = 0; i < E; ++i) {
        char type;
        cin >> type;
        if (type == 'U') {
            events[i].type = 0;
            cin >> events[i].u >> events[i].val;
            long long delta = (events[i].val - B[events[i].u]) % MOD;
            if (delta < 0) delta += MOD;
            events[i].delta = delta;
            B[events[i].u] = events[i].val;
        } else {
            events[i].type = 1;
            cin >> events[i].u;
            q_cnt++;
            events[i].k = q_cnt;
        }
    }

    long long Ans = 0;
    int S = 250; 
    vector<long long> W(N + 1, 0);
    vector<long long> Lazy(N + 1, 0);

    for (int r = E - 1; r >= 0; r -= S) {
        int l = max(0, r - S + 1);
        vector<pair<int, int>> block_queries;

        for (int i = r; i >= l; --i) {
            if (events[i].type == 1) {
                block_queries.push_back({events[i].u, events[i].k});
            } else {
                int v = events[i].u;
                long long cur_W = W[v];
                for (auto& qry : block_queries) {
                    cur_W += 1LL * qry.second * P[qry.first][v];
                }
                cur_W %= MOD;
                Ans = (Ans + events[i].delta * cur_W) % MOD;
            }
        }

        for (auto& qry : block_queries) {
            Lazy[qry.first] += qry.second;
            if (Lazy[qry.first] >= MOD) Lazy[qry.first] %= MOD;
        }

        for (int u : topo) {
            if (!Lazy[u]) continue;
            W[u] += Lazy[u];
            if (W[u] >= MOD) W[u] %= MOD;

            for (int v : adj[u]) {
                Lazy[v] += Lazy[u];
                if (Lazy[v] >= MOD) Lazy[v] -= MOD;
            }
            Lazy[u] = 0; 
        }
    }

    for (int i = 1; i <= N; ++i) {
        Ans = (Ans + 1LL * B_init[i] * W[i]) % MOD;
    }

    cout << Ans << "\n";

    return 0;
}

```

