model solution output:
### Idea

The Time Limit Exceeded (TLE) in the previous approach is primarily caused by the $O(N)$ overhead of re-initializing state arrays (`fill` on distance and visited arrays) and the dynamic memory allocation of `std::queue` during each iteration.

To optimize this, the solution uses generation arrays (or timestamps). By tracking `current_vis`, we can reset the visited state in $O(1)$ time. Additionally, using `static std::vector<int>` instead of `std::queue` prevents repeated heap allocations. The search is also simplified to purely use randomized Breadth-First Search (BFS). BFS naturally finds shortest, chordless cycles, which have a high probability of being non-separating in graphs with a minimum degree of 3.

### Complexity

* **Time Complexity:** $O(K \cdot (V_{visited} + E_{visited}))$. With the $O(1)$ state reset using timestamps, the cost of each iteration strictly depends on the number of nodes explored before a cycle is found. The worst-case total time is bounded by $O(K \cdot (N + M))$ where $K = 1000$. This executes easily within the 2.0s limit.
* **Memory Complexity:** $O(N + M)$ space. Pre-allocating linear arrays and reusing static vectors requires around 15-20 MB, well within the 1024 MB threshold.

### C++14 Solution

```cpp
#include <iostream>
#include <vector>
#include <algorithm>
#include <random>

using namespace std;

struct Edge {
    int to;
    int id;
};

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(NULL);

    int N, M;
    if (!(cin >> N >> M)) return 0;

    vector<vector<Edge>> adj(N + 1);
    for (int i = 1; i <= M; ++i) {
        int u, v;
        cin >> u >> v;
        adj[u].push_back({v, i});
        adj[v].push_back({u, i});
    }

    mt19937 rng(1337);
    for (int i = 1; i <= N; ++i) {
        shuffle(adj[i].begin(), adj[i].end(), rng);
    }

    vector<int> in_cycle(M + 1, 0);
    int cycle_tag = 0;
    
    vector<int> vis(N + 1, 0);
    int current_vis = 0;

    auto check_cycle = [&](const vector<int>& C_edges) -> bool {
        cycle_tag++;
        for (int e : C_edges) in_cycle[e] = cycle_tag;

        current_vis++;
        int visited_count = 0;
        static vector<int> q_check;
        q_check.clear();
        
        q_check.push_back(1);
        vis[1] = current_vis;
        visited_count++;

        int head = 0;
        while (head < (int)q_check.size()) {
            int u = q_check[head++];
            for (const auto& edge : adj[u]) {
                if (in_cycle[edge.id] == cycle_tag) continue;
                if (vis[edge.to] != current_vis) {
                    vis[edge.to] = current_vis;
                    visited_count++;
                    q_check.push_back(edge.to);
                }
            }
        }
        return visited_count == N;
    };

    vector<int> parent_node(N + 1, 0);
    vector<int> parent_edge(N + 1, 0);
    vector<int> depth(N + 1, 0);
    
    for (int iter = 0; iter < 1000; ++iter) {
        int S = uniform_int_distribution<int>(1, N)(rng);
        current_vis++;
        
        int u_cycle = -1, v_cycle = -1, cycle_edge_id = -1;
        
        static vector<int> q;
        q.clear();
        q.push_back(S);
