};

struct IntPoint {
    long long x, y;
    IntPoint operator-(const IntPoint& o) const { return {x - o.x, y - o.y}; }
};

long long cross(IntPoint a, IntPoint b) {
    return a.x * b.y - a.y * b.x;
}

long double cross_dbl(Point a, Point b) {
    return a.x * b.y - a.y * b.x;
}

struct Halfplane {
    Point p, v_dbl, nv;
    IntPoint p_int, v_int;
    int id;

    Halfplane() {}
    Halfplane(long long x1, long long y1, long long x2, long long y2, int _id) {
        p_int = {x1, y1};
        v_int = {x2 - x1, y2 - y1};
        p = {(long double)x1, (long double)y1};
        v_dbl = {(long double)v_int.x, (long double)v_int.y};
        long double len = sqrt(v_dbl.x * v_dbl.x + v_dbl.y * v_dbl.y);
        nv = {v_dbl.x / len, v_dbl.y / len};
        id = _id;
    }

    bool operator<(const Halfplane& o) const {
        auto half = [](IntPoint pt) {
            return pt.y > 0 || (pt.y == 0 && pt.x > 0) ? 0 : 1;
        };
        int h1 = half(v_int), h2 = half(o.v_int);
        if (h1 != h2) return h1 < h2;
        return cross(v_int, o.v_int) > 0;
    }
};

bool same_dir(const Halfplane& a, const Halfplane& b) {
    return cross(a.v_int, b.v_int) == 0 && (a.v_int.x * b.v_int.x + a.v_int.y * b.v_int.y) > 0;
}

Point intersect(const Halfplane& a, const Halfplane& b) {
    long double c = cross_dbl(a.v_dbl, b.v_dbl);
    long double num = cross_dbl(b.p - a.p, b.v_dbl);
    return a.p + a.v_dbl * (num / c);
}

