            return true;
        }
        path.pop_back();
    }

    fail_memo[u].insert(h);
    return false;
}

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(NULL);

    if (!(cin >> N >> K)) return 0;

    V.resize(N);
    for (int i = 0; i < N; ++i) {
        cin >> V[i];
    }

    nxt.assign(N + 1, vector<int>(K + 1, N));
    for (int i = N - 1; i >= 0; --i) {
        for (int c = 1; c <= K; ++c) {
            nxt[i][c] = nxt[i + 1][c];
        }
        nxt[i][V[i]] = i;
    }

    mt19937_64 rng(1337);
    zobrist.resize(K + 1);
    for (int i = 1; i <= K; ++i) {
        zobrist[i] = rng();
    }
    fail_memo.resize(N + 1);

    vector<int> avail;
    avail.reserve(K);
    for (int i = 1; i <= K; ++i) {
        avail.push_back(i);
    }
    vector<int> path;
    path.reserve(K);

    if (dfs(0, avail, path)) {
        for (int i = 0; i < K; ++i) {
            cout << path[i] << (i == K - 1 ? "" : " ");
        }
        cout << "\n";
    } else {
        cout << "*\n";
    }

    return 0;
}

