            if (vq.empty()) continue;
            
            sort(vq.begin(), vq.end(), [](const ValidQuery& a, const ValidQuery& b){
                if(a.supp_idx != b.supp_idx) return a.supp_idx < b.supp_idx;
                return a.qid < b.qid;
            });
            
            solve_dc(0, vq.size() - 1, 0, P.size() - 1, vq, P, ans, supp);
        }
    }
    
    for(int i = 0; i < s_query_count; ++i) {
        cout << ans[i] << "\n";
    }
    
    return 0;
}

model solution output:
### Main idea

The problem can be modeled as finding the maximum profit over time by choosing optimal jobs. Because every job pays the same daily rate $S$, whenever Rafael is working, his profit increases by exactly $S$ each day. The only differences between jobs are their start dates, end dates, and initial fake cover letter costs. Therefore, we should only reconsider which job Rafael should be working at "critical days": when a job becomes available (starts) or when a job is no longer available (ends).

Using a sweepline approach, we can compress the coordinate space to only these critical days (specifically $l_i - 1$, $l_i$, and $r_i$). For any active job $i$ evaluated at day $x$, the profit is given by $DP(l_i - 1) + (x - l_i + 1) \times S - c_i$, which can be refactored as $x \cdot S + (DP(l_i - 1) - (l_i - 1) \times S - c_i)$. The term in parentheses is a constant $V_i$ for each job once it starts. We can maintain these constants $V_i$ for all currently active jobs in a max-heap, enabling us to quickly determine the most profitable active job on any given day.

### Technique used

* **Coordinate Compression** to handle large time intervals (up to $10^9$).
* **Dynamic Programming (DP)** to compute the maximum profit by the end of each critical day.
* **Sweepline Algorithm** to process start and end events sequentially.
* **Priority Queue (Max-Heap) with Lazy Deletion** to efficiently keep track of the optimal active job.

### Correctness argument

Let $DP(x)$ be the maximum profit attainable by the end of day $x$. The value of $DP(x)$ is monotonically non-decreasing because doing nothing on day $x$ guarantees at least $DP(x-1)$.
When evaluating the optimal profit at day $x$, we check all active jobs. A job $i$ is active if $l_i \le x \le r_i$. If we decide to use job $i$ up to day $x$, we must have started it at $l_i$. The best profit before starting it is $DP(l_i - 1)$. The net profit at day $x$ from this path is $DP(l_i - 1) + (x - l_i + 1)S - c_i$.
By separating the $x$-dependent term from the $i$-dependent terms, we get $x \cdot S + V_i$. Between any two compressed coordinates, the set of active jobs remains constant, and since $x \cdot S$ increases linearly, the local maximum profit will always be achieved at the rightmost boundary of that interval. Hence, calculating the DP state exclusively at the compressed coordinates perfectly captures all optimal transitions. Jobs ending are cleanly filtered out of the max-heap using a lazy boolean flag checking if their end date has passed.

### Complexity analysis

* **Time Complexity:** $O(N \log N)$. Sorting the original arrays, removing duplicate coordinates, and performing `lower_bound` searches take $O(N \log N)$. The sweepline iterates exactly $M$ times (where $M \le 3N$). Pushing to and lazy-popping from the priority queue takes $O(\log N)$ per job. Thus, the overall time bound is strictly $O(N \log N)$, easily running within the 0.5 seconds limit.
* **Memory / Space Complexity:** $O(N)$. Tracking the coordinates array, the DP array, arrays for event handling, and the priority queue each require size linearly proportional to $N$. The space required peaks around $\sim$ 100 MB, well within the 1024 MB limit.

### Complete C++20 implementation

```cpp
#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>
#include <queue>

using namespace std;

struct Job {
    int id;
    long long l, r, c;
    int prev_idx;
};

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(NULL);

    int n;
    long long S;
    if (!(cin >> n >> S)) return 0;

    vector<Job> jobs(n);
    vector<long long> coords;
    coords.reserve(3 * n);

    for (int i = 0; i < n; i++) {
        jobs[i].id = i;
        cin >> jobs[i].l >> jobs[i].r >> jobs[i].c;
        coords.push_back(jobs[i].l - 1);
        coords.push_back(jobs[i].l);
        coords.push_back(jobs[i].r);
    }

    sort(coords.begin(), coords.end());
    coords.erase(unique(coords.begin(), coords.end()), coords.end());

    auto get_idx = [&](long long x) {
        return lower_bound(coords.begin(), coords.end(), x) - coords.begin();
    };

    for (int i = 0; i < n; i++) {
        jobs[i].prev_idx = get_idx(jobs[i].l - 1);
    }

    vector<int> start_order(n), end_order(n);
    iota(start_order.begin(), start_order.end(), 0);
    iota(end_order.begin(), end_order.end(), 0);

    sort(start_order.begin(), start_order.end(), [&](int a, int b) {
        return jobs[a].l < jobs[b].l;
    });

    sort(end_order.begin(), end_order.end(), [&](int a, int b) {
        return jobs[a].r < jobs[b].r;
    });

    int M = coords.size();
    vector<long long> dp(M, 0);
    vector<bool> ended(n, false);
    priority_queue<pair<long long, int>> pq;

    int start_idx = 0;
    int end_idx = 0;

    for (int k = 0; k < M; k++) {
        long long p = coords[k];
        if (k > 0) dp[k] = dp[k - 1];

        while (start_idx < n && jobs[start_order[start_idx]].l == p) {
            int id = start_order[start_idx];
            long long prev_dp = dp[jobs[id].prev_idx];
            long long V = prev_dp - (jobs[id].l - 1) * S - jobs[id].c;
            pq.push({V, id});
            start_idx++;
        }

        while (!pq.empty() && ended[pq.top().second]) {
            pq.pop();
        }

        if (!pq.empty()) {
            dp[k] = max(dp[k], p * S + pq.top().first);
        }

        while (end_idx < n && jobs[end_order[end_idx]].r == p) {
            int id = end_order[end_idx];
            ended[id] = true;
            end_idx++;
        }
    }

    cout << dp[M - 1] << "\n";
    return 0;
}

