    vector<int> pos(n + 1);
    for (int i = 0; i < n; ++i) {
        int val;
        cin >> val;
        pos[val] = i;
    }

    int blocks = 1;
    for (int i = 1; i < n; ++i) {
        if (pos[i] > pos[i + 1]) {
            blocks++;
        }
    }

    int k = 0;
    int max_blocks = 1;
    while (max_blocks < blocks) {
        max_blocks *= 2;
        k++;
    }

    cout << k << "\n";

