### Main idea

The goal is to compute the polynomial $q(x) = t(x+K) + p(x-K) \pmod{998244353}$. For a general polynomial $A(x) = \sum_{i=0}^N a_i x^i$, substituting $(x+K)$ yields:


$$A(x+K) = \sum_{i=0}^N a_i (x+K)^i = \sum_{i=0}^N a_i \sum_{j=0}^i \binom{i}{j} x^j K^{i-j}$$


Rearranging to group by $x^j$, the new coefficient $b_j$ for degree $j$ is:


$$b_j = \sum_{i=j}^N a_i \frac{i!}{j!(i-j)!} K^{i-j} = \frac{1}{j!} \sum_{i=j}^N (a_i \cdot i!) \frac{K^{i-j}}{(i-j)!}$$


By defining $u_i = a_i \cdot i!$ and $v_k = \frac{K^k}{k!}$, the term $b_j \cdot j!$ is exactly $\sum_{i=j}^N u_i v_{i-j}$. Reversing the sequence $u$ such that $U_{N-i} = u_i$, this becomes a standard convolution which can be computed rapidly using polynomial multiplication.

### Technique used

Number Theoretic Transform (NTT) for fast polynomial multiplication, combined with Combinatorics (Binomial Theorem).

### Correctness argument

By reversing the sequence $u$ into $U$, where $U_m = u_{N-m}$, the product of $U(x)$ and $V(x)$ produces a polynomial $W(x)$. The coefficient $W_{N-j}$ is the discrete convolution $\sum_{m=0}^{N-j} U_m V_{(N-j)-m}$. Expanding this matches exactly the required summation $\sum_{i=j}^N u_i v_{i-j}$. After computing $W$, simply dividing $W_{N-j}$ by $j!$ (multiplying by its modular inverse) isolates the exact shifted polynomial coefficient $b_j$. Since $t(x)$ is shifted by $K$ and $p(x)$ is shifted by $-K$, computing this operation for each independently and summing the resulting coefficients handles the objective without losing modular congruence.

### Complexity analysis

* 
**Time Complexity:** Computing the coefficients requires multiplying two polynomials of degree up to $10^5$. Using the Number Theoretic Transform, multiplying two arrays of size $N$ requires $\mathcal{O}(N \log N)$ operations. Evaluating this twice (for $t$ and $p$) maintains an overall time complexity of $\mathcal{O}(N \log N)$.


* **Memory / Space Complexity:** $\mathcal{O}(N)$ to store the initial arrays, factorial inversions, and NTT internal padding up to the nearest power of 2 ($262144$). This comfortably fits inside the generous 1024 megabytes memory limit.



### Complete C++20 implementation

```cpp
#include <iostream>
#include <vector>
#include <algorithm>

using namespace std;

const int MOD = 998244353;

long long power(long long base, long long exp) {
    long long res = 1;
    base %= MOD;
    while (exp > 0) {
        if (exp % 2 == 1) res = (res * base) % MOD;
        base = (base * base) % MOD;
        exp /= 2;
    }
    return res;
}

long long modInverse(long long n) {
    return power(n, MOD - 2);
}

void ntt(vector<long long>& a, bool invert) {
    int n = a.size();
    for (int i = 1, j = 0; i < n; i++) {
        int bit = n >> 1;
        for (; j & bit; bit >>= 1) j ^= bit;
        j ^= bit;
        if (i < j) swap(a[i], a[j]);
    }
    for (int len = 2; len <= n; len <<= 1) {
        long long wlen = power(3, (MOD - 1) / len);
        if (invert) wlen = modInverse(wlen);
        for (int i = 0; i < n; i += len) {
            long long w = 1;
            for (int j = 0; j < len / 2; j++) {
                long long u = a[i + j], v = (a[i + j + len / 2] * w) % MOD;
                a[i + j] = u + v < MOD ? u + v : u + v - MOD;
                a[i + j + len / 2] = u - v >= 0 ? u - v : u - v + MOD;
                w = (w * wlen) % MOD;
            }
        }
    }
    if (invert) {
        long long n_inv = modInverse(n);
        for (long long& x : a) x = (x * n_inv) % MOD;
    }
}

vector<long long> multiply(const vector<long long>& a, const vector<long long>& b) {
    if (a.empty() || b.empty()) return {};
    vector<long long> fa(a.begin(), a.end()), fb(b.begin(), b.end());
    int n = 1;
    while (n < a.size() + b.size()) n <<= 1;
    fa.resize(n); fb.resize(n);
    ntt(fa, false); ntt(fb, false);
    for (int i = 0; i < n; i++) fa[i] = (fa[i] * fb[i]) % MOD;
    ntt(fa, true);
    int res_size = a.size() + b.size() - 1;
    vector<long long> result(res_size);
    for (int i = 0; i < res_size; i++) result[i] = fa[i];
    return result;
}

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(NULL);

    int N;
    long long K;
    if (!(cin >> N >> K)) return 0;

    vector<long long> t(N + 1), p(N + 1);
    for (int i = 0; i <= N; i++) cin >> t[i];
    for (int i = 0; i <= N; i++) cin >> p[i];

    vector<long long> fact(N + 1), inv_fact(N + 1);
    fact[0] = 1; inv_fact[0] = 1;
    for (int i = 1; i <= N; i++) {
        fact[i] = fact[i - 1] * i % MOD;
    }
    inv_fact[N] = modInverse(fact[N]);
    for (int i = N - 1; i >= 1; i--) {
        inv_fact[i] = inv_fact[i + 1] * (i + 1) % MOD;
    }

    auto shift_polynomial = [&](const vector<long long>& poly, long long shift) {
        shift = (shift % MOD + MOD) % MOD;
        vector<long long> U(N + 1), V(N + 1);
        for (int i = 0; i <= N; i++) U[N - i] = poly[i] * fact[i] % MOD;
        
        long long shift_pow = 1;
        for (int i = 0; i <= N; i++) {
            V[i] = shift_pow * inv_fact[i] % MOD;
            shift_pow = shift_pow * shift % MOD;
        }
        
        vector<long long> W = multiply(U, V);
        vector<long long> res(N + 1);
        for (int j = 0; j <= N; j++) {
            res[j] = W[N - j] * inv_fact[j] % MOD;
        }
        return res;
    };

    vector<long long> t_shifted = shift_polynomial(t, K);
    vector<long long> p_shifted = shift_polynomial(p, -K);

    for (int i = 0; i <= N; i++) {
        long long ans = (t_shifted[i] + p_shifted[i]) % MOD;
        cout << ans << (i == N ? "" : " ");
    }
    cout << "\n";

    return 0;
}

