model solution output:
### 1. Solution Idea

For each vertex $u$, the goal is to find the shortest path to all its neighbors $v$ without using the direct edge $(u, v)$. This is equivalent to finding the shortest cycle containing $u$ that goes through $v$.

We can solve this by running a modified single-source shortest path (Dijkstra's algorithm) from every vertex $s \in [1, N]$. To avoid traversing the direct edge $(s, v)$ when computing the detour for $v$, we maintain the shortest and second-shortest path distances to every node, ensuring they originate from *different* initial edges leaving $s$.

During the traversal, we explicitly forbid any path from returning to the source $s$. Since edge weights are strictly positive, an optimal simple path detour would never revisit the starting node anyway. This correctly prevents the path from later traversing any edge incident to $s$, including the direct edge $(s, v)$ in reverse. After the algorithm finishes for source $s$, the detour for an edge $(s, v)$ is simply the minimum distance recorded at $v$ whose initial starting edge was not $v$.

### 2. Complexity Analysis

* **Time Complexity:** $\mathcal{O}(N \cdot M \log N)$. We run the modified Dijkstra from all $N$ vertices. For each execution, we maintain at most 2 state entries per vertex. The priority queue processes at most $2N$ states, and we relax at most $2M$ edges. Each priority queue operation takes $\mathcal{O}(\log N)$, resulting in $\mathcal{O}(M \log N)$ per source. The total time comfortably passes the 5.0 seconds limit  for $N \le 300$ and $M \le 45000$.


* **Memory Complexity:** $\mathcal{O}(N + M)$. The adjacency list requires $\mathcal{O}(M)$ space. The distance array for the modified Dijkstra stores at most 2 elements per vertex, taking $\mathcal{O}(N)$ space. This fully satisfies the 1024 megabytes memory limit.



### 3. C++14 Implementation

```cpp
#include <iostream>
#include <vector>
#include <queue>
#include <tuple>
#include <algorithm>

using namespace std;

const long long INF = 1e18;

struct Edge {
    int to;
    long long w;
    int id;
};

struct Entry {
    long long d;
    int first_node;
    bool operator<(const Entry& o) const {
        return d < o.d;
    }
};

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(NULL);

    int n, m;
    if (!(cin >> n >> m)) return 0;

    vector<vector<Edge>> adj(n + 1);
    for (int i = 0; i < m; ++i) {
        int u, v;
        long long w;
        cin >> u >> v >> w;
        adj[u].push_back({v, w, i});
        adj[v].push_back({u, w, i});
    }

    vector<long long> ans(m, INF);

    for (int s = 1; s <= n; ++s) {
        vector<vector<Entry>> dist(n + 1);
        priority_queue<tuple<long long, int, int>, vector<tuple<long long, int, int>>, greater<tuple<long long, int, int>>> pq;

        for (const auto& edge : adj[s]) {
            dist[edge.to].push_back({edge.w, edge.to});
            pq.push(make_tuple(edge.w, edge.to, edge.to));
        }

        while (!pq.empty()) {
            long long d;
            int u, first_node;
            tie(d, u, first_node) = pq.top();
            pq.pop();

            bool valid = false;
            for (const auto& entry : dist[u]) {
                if (entry.first_node == first_node) {
                    if (d <= entry.d) valid = true;
                    break;
                }
            }
            if (!valid) continue;

            for (const auto& edge : adj[u]) {
                int v = edge.to;
                if (v == s) continue;

                long long w = edge.w;
                long long new_d = d + w;

                int found_idx = -1;
                for (size_t i = 0; i < dist[v].size(); ++i) {
                    if (dist[v][i].first_node == first_node) {
                        found_idx = i;
                        break;
                    }
                }

                if (found_idx != -1) {
                    if (new_d < dist[v][found_idx].d) {
                        dist[v][found_idx].d = new_d;
                        sort(dist[v].begin(), dist[v].end());
                        pq.push(make_tuple(new_d, v, first_node));
                    }
                } else {
                    if (dist[v].size() < 2) {
                        dist[v].push_back({new_d, first_node});
                        sort(dist[v].begin(), dist[v].end());
                        pq.push(make_tuple(new_d, v, first_node));
                    } else if (new_d < dist[v].back().d) {
                        dist[v].back() = {new_d, first_node};
                        sort(dist[v].begin(), dist[v].end());
                        pq.push(make_tuple(new_d, v, first_node));
                    }
                }
            }
        }

        for (const auto& edge : adj[s]) {
            int v = edge.to;
            int id = edge.id;
            for (const auto& entry : dist[v]) {
                if (entry.first_node != v) {
                    if (entry.d < ans[id]) {
                        ans[id] = entry.d;
                    }
                }
            }
        }
    }

    for (int i = 0; i < m; ++i) {
        if (ans[i] == INF) {
            cout << -1 << "\n";
        } else {
            cout << ans[i] << "\n";
        }
    }

    return 0;
}

