    Edge *e = make_edge(a->sym->org, b->org);
    splice(e, a->sym->oprev);
    splice(e->sym, b);
    return e;
}

void delete_edge(Edge *e) {
    splice(e, e->oprev);
    splice(e->sym, e->sym->oprev);
    e->deleted = true;
    e->sym->deleted = true;
}

bool right_of(int p, Edge *e) {
    return cross(pts[e->org], pts[e->sym->org], pts[p]) > 0;
}

bool left_of(int p, Edge *e) {
    return cross(pts[e->org], pts[e->sym->org], pts[p]) < 0;
}

pair<Edge*, Edge*> build_delaunay(int l, int r) {
    if (r - l + 1 == 2) {
        Edge *e = make_edge(l, r);
        return {e, e->sym};
    }
    if (r - l + 1 == 3) {
        Edge *a = make_edge(l, l + 1);
        Edge *b = make_edge(l + 1, r);
        splice(a->sym, b);
        ll c = cross(pts[l], pts[l + 1], pts[r]);
        if (c > 0) {
            connect(b, a);
            return {a, b->sym};
        } else if (c < 0) {
            Edge *c_edge = connect(b, a);
            return {c_edge->sym, c_edge};
        } else {
            return {a, b->sym};
        }
    }

    int mid = (l + r) / 2;
    auto l_res = build_delaunay(l, mid);
    auto r_res = build_delaunay(mid + 1, r);
    Edge *ldo = l_res.first, *ldi = l_res.second;
    Edge *rdi = r_res.first, *rdo = r_res.second;

    while (true) {
        if (left_of(rdi->org, ldi)) ldi = ldi->sym->oprev;
        else if (right_of(ldi->org, rdi)) rdi = rdi->onext;
        else break;
    }

    Edge *base = connect(rdi->sym, ldi);
    if (ldi->org == ldo->org) ldo = base->sym;
    if (rdi->org == rdo->org) rdo = base;

    while (true) {
        Edge *lcand = base->sym->onext;
        if (right_of(lcand->sym->org, base)) {
            while (in_circle(pts[base->sym->org], pts[base->org], pts[lcand->sym->org], pts[lcand->onext->sym->org])) {
                Edge *t = lcand->onext;
                delete_edge(lcand);
                lcand = t;
            }
        }
        Edge *rcand = base->oprev;
        if (right_of(rcand->org, base)) {
            while (in_circle(pts[base->sym->org], pts[base->org], pts[rcand->org], pts[rcand->oprev->org])) {
                Edge *t = rcand->oprev;
                delete_edge(rcand);
                rcand = t;
            }
        }
        bool v_lcand = right_of(lcand->sym->org, base);
        bool v_rcand = right_of(rcand->org, base);
        if (!v_lcand && !v_rcand) break;
        if (v_lcand && v_rcand && in_circle(pts[base->sym->org], pts[base->org], pts[lcand->sym->org], pts[rcand->org])) {
            base = connect(rcand, base->sym);
        } else {
            base = connect(base->sym, lcand->sym);
        }
    }
    return {ldo, rdo};
}

struct Node {
    int pt_idx;
    int left, right;
} kdtree[100005];

int kd_sz = 0;

int kd_build(int l, int r, int depth) {
    if (l > r) return 0;
    int mid = (l + r) / 2;
    if (depth % 2 == 0) {
        nth_element(indices + l, indices + mid, indices + r + 1, [](int a, int b) {
            return pts[a].x < pts[b].x;
        });
    } else {
        nth_element(indices + l, indices + mid, indices + r + 1, [](int a, int b) {
            return pts[a].y < pts[b].y;
        });
    }
    int u = ++kd_sz;
    kdtree[u].pt_idx = indices[mid];
    kdtree[u].left = kd_build(l, mid - 1, depth + 1);
    kdtree[u].right = kd_build(mid + 1, r, depth + 1);
    return u;
}

double min_dist_sq;

void kd_query(int u, double x, double y, int depth) {
    if (!u) return;
    int p = kdtree[u].pt_idx;
    double dx = x - pts[p].x;
    double dy = y - pts[p].y;
    double d2 = dx * dx + dy * dy;
    if (d2 < min_dist_sq) min_dist_sq = d2;

    double axis_dist = (depth % 2 == 0) ? (x - pts[p].x) : (y - pts[p].y);
    int first = kdtree[u].left, second = kdtree[u].right;
    if (axis_dist > 0) swap(first, second);

    kd_query(first, x, y, depth + 1);
    if (axis_dist * axis_dist < min_dist_sq) {
        kd_query(second, x, y, depth + 1);
    }
}

pair<double, double> get_circumcenter(Point A, Point B, Point C) {
    double D = 2.0 * (A.x * (B.y - C.y) + B.x * (C.y - A.y) + C.x * (A.y - B.y));
    if (abs(D) < 1e-9) return {1e9, 1e9};
    double ax2 = (double)A.x * A.x + (double)A.y * A.y;
    double bx2 = (double)B.x * B.x + (double)B.y * B.y;
    double cx2 = (double)C.x * C.x + (double)C.y * C.y;
    double cx = (ax2 * (B.y - C.y) + bx2 * (C.y - A.y) + cx2 * (A.y - B.y)) / D;
    double cy = (ax2 * (C.x - B.x) + bx2 * (A.x - C.x) + cx2 * (B.x - A.x)) / D;
    return {cx, cy};
}

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(NULL);

    double Xmin = 1e9, Xmax = -1e9, Ymin = 1e9, Ymax = -1e9;
    for (int i = 0; i < 4; i++) {
        double x, y;
        if (!(cin >> x >> y)) return 0;
        Xmin = min(Xmin, x);
        Xmax = max(Xmax, x);
        Ymin = min(Ymin, y);
        Ymax = max(Ymax, y);
    }

    int N;
    if (!(cin >> N)) return 0;

    for (int i = 0; i < N; i++) {
        cin >> pts[i].x >> pts[i].y;
        pts[i].id = i;
    }

    sort(pts, pts + N);
    N = unique(pts, pts + N) - pts;

    for (int i = 0; i < N; i++) indices[i] = i;
    int kd_root = kd_build(0, N - 1, 0);

    vector<pair<int, int>> delaunay_edges;
    double ans = 0;

    if (N >= 2) {
        build_delaunay(0, N - 1);
        for (Edge* e : all_edges) {
            if (e->deleted) continue;
            int u = e->org, v = e->sym->org;
            if (u < v) delaunay_edges.push_back({u, v});
            
            Edge *e1 = e;
            Edge *e2 = e1->sym->onext;
            Edge *e3 = e2->sym->onext;
            if (e3->sym->onext == e1) {
                int w = e3->org;
                if (u < v && u < w) {
                    if (cross(pts[u], pts[v], pts[w]) > 0) {
                        pair<double, double> cc = get_circumcenter(pts[u], pts[v], pts[w]);
                        double cx = cc.first, cy = cc.second;
                        if (cx >= Xmin && cx <= Xmax && cy >= Ymin && cy <= Ymax) {
                            double d = sqrt((cx - pts[u].x) * (cx - pts[u].x) + (cy - pts[u].y) * (cy - pts[u].y));
                            ans = max(ans, d);
                        }
                    }
                }
            }
        }
    }

    auto add_candidate = [&](double ix, double iy) {
        if (ix >= Xmin - 1e-7 && ix <= Xmax + 1e-7 && iy >= Ymin - 1e-7 && iy <= Ymax + 1e-7) {
            ix = max(Xmin, min(Xmax, ix));
            iy = max(Ymin, min(Ymax, iy));
            min_dist_sq = 1e18;
            kd_query(kd_root, ix, iy, 0);
            ans = max(ans, sqrt(min_dist_sq));
        }
    };

    for (auto& edge : delaunay_edges) {
        Point A = pts[edge.first];
        Point B = pts[edge.second];
        double a = B.x - A.x;
        double b = B.y - A.y;
        double xm = (A.x + B.x) / 2.0;
        double ym = (A.y + B.y) / 2.0;
        double c = -a * xm - b * ym;

        if (abs(b) > 1e-9) {
            add_candidate(Xmin, (-c - a * Xmin) / b);
            add_candidate(Xmax, (-c - a * Xmax) / b);
        }
        if (abs(a) > 1e-9) {
            add_candidate((-c - b * Ymin) / a, Ymin);
            add_candidate((-c - b * Ymax) / a, Ymax);
        }
    }

    double corners[4][2] = {
        {Xmin, Ymin}, {Xmax, Ymin}, {Xmax, Ymax}, {Xmin, Ymax}
    };

    for (int i = 0; i < 4; i++) {
        min_dist_sq = 1e18;
        kd_query(kd_root, corners[i][0], corners[i][1], 0);
        ans = max(ans, sqrt(min_dist_sq));
    }

    cout << fixed << setprecision(10) << ans << "\n";
    return 0;
}

