model solution output:
### **Main idea**

The problem requires finding the first player (in the given order) whose line equation $Y_i < A_j X_i + B_j$ covers a specific token $(X_i, Y_i)$. Given the large number of tokens and players, testing each point against every player sequentially is too slow. Instead, the condition can be rewritten as checking if the maximum value of $A_j X_i + B_j$ for a set of players is strictly greater than $Y_i$.

By arranging the players into a Segment Tree, each node can represent a range of players and store the upper envelope of their lines. To answer a query for a token $(X_i, Y_i)$, we start at the root and ask: *Does any line in this range evaluate to a value greater than $Y_i$ at $x = X_i$?* If not, the token is not covered by any player in this subtree. If it is, we prioritize searching the left child (which represents players that come earlier in the turn order) to find the first eligible player. We only search the right child if the left child cannot cover the token.

### **Technique used**

* **Segment Tree**: To maintain ranges of players and enforce the chronological turn-order evaluation.
* **Convex Hull Trick (Upper Envelope)**: To quickly evaluate the maximum $y$-value among a subset of lines at a given $x$-coordinate.
* **Binary Search**: To query the optimum line for a given $x$ from the precomputed upper envelope in $O(\log(\text{size}))$ time.

### **Correctness argument**

A player $j$ captures a token at $(X_i, Y_i)$ if $Y_i < A_j X_i + B_j$ and no player $k < j$ already captured it.
Each node in our Segment Tree representing the range of players $[L, R]$ maintains the upper convex hull of their lines. Evaluating this hull at $X_i$ gives the theoretical maximum $y$-value any player in $[L, R]$ can achieve at that $x$-coordinate.
If $\max(A_j X_i + B_j) \le Y_i$, no player in $[L, R]$ can possibly take the token, allowing us to completely prune this subtree. When the maximum is strictly greater than $Y_i$, a valid player is guaranteed to exist. By recursively checking the left child before the right child, we inherently satisfy the requirement of assigning the token to the player with the smallest possible index.

### **Complexity analysis**

* **Time Complexity:** * **Building:** Sorting and merging the lines at each level of the Segment Tree takes linear time relative to the number of elements. Across all $O(\log P)$ levels, building the Segment Tree and all Convex Hulls takes $O(P \log P)$ time.
* **Querying:** A single token's query visits at most $O(\log P)$ nodes. At each node, evaluating the upper envelope takes $O(\log P)$ using binary search. The query time per token is $O(\log^2 P)$. For $T$ tokens, the total query time is $O(T \log^2 P)$.
* **Total Time Complexity:** $O(P \log P + T \log^2 P)$. This effortlessly executes within the generous 2.5 seconds time limit.


* **Memory Complexity:** Each line belongs to exactly one node per level of the Segment Tree. Storing the upper envelopes across $\approx \log_2 P$ levels takes $O(P \log P)$ space. This is highly efficient and easily stays within the 1024 megabytes limit.



### **Complete C++20 implementation**

```cpp
#include <iostream>
#include <vector>
#include <algorithm>
#include <iterator>

using namespace std;

struct Line {
    long long a, b;
    int id;
};

struct Node {
    vector<Line> hull;
    vector<double> startX;
};

int T;
vector<pair<long long, long long>> tokens;
int P;
vector<Line> lines_input;
vector<Node> tree_nodes;

double intersect(const Line& l1, const Line& l2) {
    return (double)(l2.b - l1.b) / (l1.a - l2.a);
}

vector<Line> build(int node, int l, int r) {
    if (l == r) {
        tree_nodes[node].hull.push_back(lines_input[l]);
        tree_nodes[node].startX.push_back(-1e18);
        return {lines_input[l]};
    }
    int mid = l + (r - l) / 2;
    vector<Line> left_lines = build(2 * node, l, mid);
    vector<Line> right_lines = build(2 * node + 1, mid + 1, r);

    vector<Line> merged;
    merged.reserve(left_lines.size() + right_lines.size());
    int i = 0, j = 0;
    while (i < left_lines.size() && j < right_lines.size()) {
        bool use_left = false;
        if (left_lines[i].a != right_lines[j].a) {
            use_left = left_lines[i].a < right_lines[j].a;
        } else {
            use_left = left_lines[i].b < right_lines[j].b;
        }
        if (use_left) {
            merged.push_back(left_lines[i++]);
        } else {
            merged.push_back(right_lines[j++]);
        }
    }
    while (i < left_lines.size()) merged.push_back(left_lines[i++]);
    while (j < right_lines.size()) merged.push_back(right_lines[j++]);

    vector<Line> filtered;
    for (const auto& L : merged) {
        if (!filtered.empty() && filtered.back().a == L.a) {
            filtered.pop_back();
        }
        filtered.push_back(L);
    }

    for (const auto& L : filtered) {
        while (tree_nodes[node].hull.size() >= 2) {
            double x = intersect(tree_nodes[node].hull.back(), L);
            if (x <= tree_nodes[node].startX.back()) {
                tree_nodes[node].hull.pop_back();
                tree_nodes[node].startX.pop_back();
            } else {
                break;
            }
        }
        if (tree_nodes[node].hull.empty()) {
            tree_nodes[node].hull.push_back(L);
            tree_nodes[node].startX.push_back(-1e18);
        } else {
            double x = intersect(tree_nodes[node].hull.back(), L);
            tree_nodes[node].hull.push_back(L);
            tree_nodes[node].startX.push_back(x);
        }
    }
    return merged;
}

long long evaluate_max(int node, long long X) {
    auto it = upper_bound(tree_nodes[node].startX.begin(), tree_nodes[node].startX.end(), (double)X);
    --it;
    int idx = distance(tree_nodes[node].startX.begin(), it);
    return tree_nodes[node].hull[idx].a * X + tree_nodes[node].hull[idx].b;
}

int query(int node, int l, int r, long long X, long long Y) {
    if (evaluate_max(node, X) <= Y) {
        return -1;
    }
    if (l == r) {
        return l;
    }
    int mid = l + (r - l) / 2;
    int res = query(2 * node, l, mid, X, Y);
    if (res != -1) return res;
    return query(2 * node + 1, mid + 1, r, X, Y);
}

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(NULL);

    if (!(cin >> T)) return 0;

    tokens.resize(T + 1);
    for (int i = 1; i <= T; ++i) {
        cin >> tokens[i].first >> tokens[i].second;
    }

    cin >> P;
    lines_input.resize(P + 1);
    for (int i = 1; i <= P; ++i) {
        cin >> lines_input[i].a >> lines_input[i].b;
        lines_input[i].id = i;
    }

    tree_nodes.resize(4 * P + 1);
    build(1, 1, P);

    vector<vector<int>> ans(P + 1);
    for (int i = 1; i <= T; ++i) {
        int p = query(1, 1, P, tokens[i].first, tokens[i].second);
        if (p != -1) {
            ans[p].push_back(i);
        }
    }

    for (int i = 1; i <= P; ++i) {
        cout << ans[i].size();
        for (int t : ans[i]) {
            cout << " " << t;
        }
        cout << "\n";
    }

    return 0;
}

