model solution output:
### Main idea

The problem asks us to find if a given point $P$ (a minor power plant) can form a collinear triplet with a point $p_1$ from polygon $A$ (first major power plant) and $p_2$ from polygon $B$ (second major power plant), such that one of the points is exactly the midpoint of the other two.

This leads to three possible cases for $P$:

1. $P$ is the midpoint of $p_1$ and $p_2$: $P = \frac{p_1 + p_2}{2} \implies 2P = p_1 + p_2$.
2. $p_1$ is the midpoint of $P$ and $p_2$: $p_1 = \frac{P + p_2}{2} \implies P = 2p_1 - p_2$.
3. $p_2$ is the midpoint of $P$ and $p_1$: $p_2 = \frac{P + p_1}{2} \implies P = 2p_2 - p_1$.

We can treat the polygons $A$ and $B$ as sets of points. The condition translates to checking if $P$ falls into one of three new convex polygons formed by the Minkowski sum of appropriately scaled and negated versions of $A$ and $B$:

* $S_1 = A + B$, and we check if $2P \in S_1$
* $S_2 = 2A + (-B)$, and we check if $P \in S_2$
* $S_3 = 2B + (-A)$, and we check if $P \in S_3$

### Technique used

**Computational Geometry: Minkowski Sum and Point-in-Convex-Polygon Detection.**

Since $A$ and $B$ are convex, their Minkowski sums are also convex. We can compute the Minkowski sum of two convex polygons in $O(M_1 + M_2)$ by merging their edge vectors sorted by polar angle. Afterward, applying the standard Monotone Chain Convex Hull cleans up collinearities and returns a strict convex polygon. Finally, for each of the $N$ query points, we can determine if it lies inside a convex polygon in $O(\log V)$ using binary search.

### Correctness argument

Scaling a convex polygon ($2A$, $2B$) or reflecting it through the origin ($-A$, $-B$) preserves convexity. The Minkowski sum of two convex polygons maps precisely to all possible linear combinations of points chosen from the respective regions, encompassing their entire areas including borders.

When generating the Minkowski sum, traversing the edge vectors in order of their polar angles rigorously constructs the boundary of the maximal combined region. Applying a convex hull algorithm onto these prefix sums filters out any degenerate or collinear vertices smoothly. For each candidate point, $O(\log V)$ point-in-convex-polygon queries accurately determine if it's bounded by the extreme rays from an origin vertex and falls onto the internal side of the opposing closing edge, rigorously answering membership even on boundary limits.

### Complexity analysis

* **Time Complexity:** - **Preprocessing (Minkowski Sums & Convex Hulls):** Generating the Minkowski sums and running the convex hull takes $O((M_1 + M_2) \log(M_1 + M_2))$ overall, dominated by the angular sort of edges and monotone chain.
* **Queries:** Each query requires three point-in-convex-polygon checks via binary search, taking $O(\log(M_1 + M_2))$ time per query. For $N$ queries, this is $O(N \log(M_1 + M_2))$.
* **Total Time Complexity:** $\mathcal{O}((M_1 + M_2) \log(M_1 + M_2) + N \log(M_1 + M_2))$. Perfectly efficient for $M_1, M_2 \le 10^5$ and $N \le 5 \times 10^5$.


* **Memory/Space Complexity:** $\mathcal{O}(M_1 + M_2 + N)$ to store the original vertices, vectors for the transformed boundaries, and query points. This comfortably satisfies the $1024$ MB limit.

### Complete C++20 implementation

```cpp
#include <iostream>
#include <vector>
#include <algorithm>
#include <string>

using namespace std;
using ll = long long;

struct Point {
    ll x, y;
    Point operator+(const Point& o) const { return {x + o.x, y + o.y}; }
    Point operator-(const Point& o) const { return {x - o.x, y - o.y}; }
    bool operator==(const Point& o) const { return x == o.x && y == o.y; }
};

ll cross(Point a, Point b) {
    return a.x * b.y - a.y * b.x;
}

vector<Point> convex_hull(vector<Point>& pts) {
    sort(pts.begin(), pts.end(), [](const Point& a, const Point& b) {
        return a.x < b.x || (a.x == b.x && a.y < b.y);
    });
    pts.erase(unique(pts.begin(), pts.end()), pts.end());
    if (pts.size() <= 2) return pts;

    vector<Point> hull;
    for (int i = 0; i < pts.size(); i++) {
        while (hull.size() >= 2 && cross(hull.back() - hull[hull.size()-2], pts[i] - hull.back()) <= 0)
            hull.pop_back();
        hull.push_back(pts[i]);
    }
    int lower_size = hull.size();
    for (int i = (int)pts.size() - 2; i >= 0; i--) {
        while (hull.size() > lower_size && cross(hull.back() - hull[hull.size()-2], pts[i] - hull.back()) <= 0)
            hull.pop_back();
        hull.push_back(pts[i]);
    }
    hull.pop_back();
    return hull;
}

vector<Point> get_minkowski(vector<Point> A, vector<Point> B) {
    auto reorder = [](vector<Point>& P) {
        int pos = 0;
        for (int i = 1; i < P.size(); i++) {
            if (P[i].y < P[pos].y || (P[i].y == P[pos].y && P[i].x < P[pos].x))
                pos = i;
        }
        rotate(P.begin(), P.begin() + pos, P.end());
    };
    reorder(A); 
    reorder(B);

    vector<Point> edges;
    edges.reserve(A.size() + B.size());
    for (int i = 0; i < A.size(); i++) edges.push_back(A[(i+1)%A.size()] - A[i]);
    for (int i = 0; i < B.size(); i++) edges.push_back(B[(i+1)%B.size()] - B[i]);

    auto cmp = [](const Point& a, const Point& b) {
        auto half = [](const Point& p) {
            return p.y > 0 || (p.y == 0 && p.x > 0);
        };
        bool ha = half(a), hb = half(b);
        if (ha != hb) return ha > hb;
        return cross(a, b) > 0;
    };

    sort(edges.begin(), edges.end(), cmp);

    vector<Point> pts;
    pts.reserve(edges.size() + 1);
    Point cur = A[0] + B[0];
    pts.push_back(cur);
    for (const auto& e : edges) {
        cur = cur + e;
        pts.push_back(cur);
    }
    return convex_hull(pts);
}

bool in_convex_poly(const vector<Point>& poly, Point p) {
    int n = poly.size();
    if (n < 3) return false;

    if (cross(poly[1] - poly[0], p - poly[0]) < 0) return false;
    if (cross(poly[n-1] - poly[0], p - poly[0]) > 0) return false;

    int l = 1, r = n - 1;
    while (r - l > 1) {
        int mid = l + (r - l) / 2;
        if (cross(poly[mid] - poly[0], p - poly[0]) >= 0) {
            l = mid;
        } else {
            r = mid;
        }
    }
    return cross(poly[l+1] - poly[l], p - poly[l]) >= 0;
}

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(NULL);

    int m1;
    if (!(cin >> m1)) return 0;
    vector<Point> A(m1);
    for (int i = 0; i < m1; i++) cin >> A[i].x >> A[i].y;

    int m2;
    cin >> m2;
    vector<Point> B(m2);
    for (int i = 0; i < m2; i++) cin >> B[i].x >> B[i].y;

    int n;
    cin >> n;
    vector<Point> P(n);
    for (int i = 0; i < n; i++) cin >> P[i].x >> P[i].y;

    vector<Point> A2 = A, B2 = B, negA = A, negB = B;
    for (auto& p : A2) { p.x *= 2; p.y *= 2; }
    for (auto& p : B2) { p.x *= 2; p.y *= 2; }
    for (auto& p : negA) { p.x = -p.x; p.y = -p.y; }
    for (auto& p : negB) { p.x = -p.x; p.y = -p.y; }

    vector<Point> S1 = get_minkowski(A, B);
    vector<Point> S2 = get_minkowski(A2, negB);
    vector<Point> S3 = get_minkowski(B2, negA);

    string ans = "";
    ans.reserve(n);
    for (int i = 0; i < n; i++) {
        Point p2 = {P[i].x * 2, P[i].y * 2};
        if (in_convex_poly(S1, p2) || in_convex_poly(S2, P[i]) || in_convex_poly(S3, P[i])) {
            ans += "Y";
        } else {
            ans += "N";
        }
    }

    cout << ans << "\n";
    return 0;
}

