model solution output:
### Main idea

The problem requires calculating the number of ways to traverse from stone $1$ to stone $N$ using jumps up to distance $10$, while accumulating at most $K$ total energy points. Standard dynamic programming approaches tracking energy and distance would fail because $N$ is up to $10^9$, massively exceeding the bounds of a direct state array iteration despite the generous 15 seconds time limit. However, because the jump distances $d_j$ are small ($d_j \le 10$), the distance transitions act precisely as a constant-order linear recurrence.

We can map energy cost to a polynomial ring, replacing integers with polynomials in $y$ evaluated modulo $y^{K+1}$ and performing all coefficient accumulations modulo $10^9$. Instead of building the entire path sequentially, we execute binary exponentiation using Fiduccia's algorithm (polynomial exponentiation over the characteristic polynomial of the recurrence) to leap straight to the $(N-1)$-th term.

### Technique used

* 
**Dynamic Programming over Polynomials**: Managing states not as scalar integers but as polynomial frequency maps (up to degree $K$) capturing energy expenditure bounds.


* **Linear Recurrence**: Expressing the DP relation purely over distances $1 \dots 10$ natively mapped into a characteristic polynomial.
* 
**Fiduccia's Algorithm**: Utilizing $O(\log N)$ polynomial multiplications—modulo the degree-$10$ characteristic recurrence polynomial—to find the base combinations needed to represent the final state at $N$.



### Correctness argument

Let $A_i$ be a state polynomial where its $c$-th coefficient defines the exact number of valid jump sequences to land exactly at distance $i$ expending $c$ energy.
The DP transition forms the relation $A_i = \sum_{d=1}^{10} C_d \times A_{i-d}$, where the coefficient $C_d$ is a polynomial such that its $p$-th degree strictly holds the initial counts of jump choices of distance $d$ and energy $p$.

The sequence generator gives the characteristic polynomial $P(X) = X^{10} - \sum_{d=1}^{10} C_d X^{10-d}$. Finding the $N-1$ state reduces to calculating $X^{N-1} \pmod{P(X)}$ utilizing binary exponentiation. The remainder translates directly into coefficients $R_i$ for the base cases $A_0 \dots A_9$. The correct polynomial at distance $N-1$ naturally follows as $\sum R_i A_i$, meaning its total sum of integer coefficients gives exactly the valid ways under the global energy limit $K$.

### Complexity analysis

* 
**Time Complexity**: $\mathcal{O}(D^2 \cdot K^2 \cdot \log N)$, where $D \le 10$ is the maximal distance constraint. Squaring a polynomial mapping to energy takes $\mathcal{O}(K^2)$, and resolving the inner recurrence logic takes $\mathcal{O}(D^2)$. This is multiplied over $\log_2(N)$ iterations representing the exponentiation phases. In the worst case, this translates to $100 \times 160000 \times 30 \approx 4.8 \times 10^8$ simple integer accumulative operations. By exploiting wide unrolled additions inside arrays, this completes securely in a fraction of a second, profoundly beating the 15 seconds limit.


* 
**Space / Memory Complexity**: $\mathcal{O}(D \cdot K)$, as the runtime memory stores only local vectors up to the $10$ distances bounding $K \le 400$. This allocates single-digit kilobytes which fits comfortably inside the 1024 megabytes constraint.



### Complete C++20 implementation

```cpp
#pragma GCC optimize("O3,unroll-loops")
#pragma GCC target("avx2,bmi,bmi2,lzcnt,popcnt")

#include <iostream>
#include <vector>
#include <cstring>
#include <algorithm>

using namespace std;

const int MOD = 1000000000;
int K;

struct PolyX {
    vector<vector<int>> coefs;
    PolyX() {}
    PolyX(int size) {
        coefs.resize(size, vector<int>(K + 1, 0));
    }
};

PolyX mul_X(const PolyX& A, const PolyX& B) {
    int new_size = A.coefs.size() + B.coefs.size() - 1;
    PolyX res(new_size);
    static unsigned long long tmp[405];
    for (int k = 0; k < new_size; ++k) {
        memset(tmp, 0, sizeof(unsigned long long) * (K + 1));
        for (int i = 0; i <= k; ++i) {
            int j = k - i;
            if (i < (int)A.coefs.size() && j < (int)B.coefs.size()) {
                const auto& polyA = A.coefs[i];
                const auto& polyB = B.coefs[j];
                for (int x = 0; x <= K; ++x) {
                    if (!polyA[x]) continue;
                    unsigned long long ax = polyA[x];
                    for (int y = 0; y <= K - x; ++y) {
                        tmp[x + y] += ax * polyB[y];
                    }
                    if (x % 8 == 7) {
                        for (int z = 0; z <= K; ++z) tmp[z] %= MOD;
                    }
                }
                for (int z = 0; z <= K; ++z) tmp[z] %= MOD;
            }
        }
        for (int x = 0; x <= K; ++x) res.coefs[k][x] = tmp[x] % MOD;
    }
    return res;
}

PolyX mod_X(PolyX A, const vector<vector<int>>& C) {
    static unsigned long long tmp[405];
    for (int i = (int)A.coefs.size() - 1; i >= 10; --i) {
        bool zero = true;
        for(int x = 0; x <= K; ++x) {
            if (A.coefs[i][x] > 0) { zero = false; break; }
        }
        if (zero) continue;

        for (int d = 1; d <= 10; ++d) {
            memset(tmp, 0, sizeof(unsigned long long) * (K + 1));
            const auto& polyA = A.coefs[i];
            const auto& polyC = C[d];
            for (int x = 0; x <= K; ++x) {
                if (!polyA[x]) continue;
                unsigned long long ax = polyA[x];
                for (int y = 0; y <= K - x; ++y) {
                    tmp[x + y] += ax * polyC[y];
                }
                if (x % 8 == 7) {
                    for (int z = 0; z <= K; ++z) tmp[z] %= MOD;
                }
            }
            for (int z = 0; z <= K; ++z) {
                A.coefs[i - d][z] = (A.coefs[i - d][z] + tmp[z]) % MOD;
            }
        }
    }
    if (A.coefs.size() > 10) {
        A.coefs.resize(10);
    }
    return A;
}

PolyX power_X(long long exp, const vector<vector<int>>& C) {
    PolyX res(1);
    res.coefs[0][0] = 1;
    PolyX base(2);
    base.coefs[1][0] = 1;

    while (exp > 0) {
        if (exp % 2 == 1) {
            res = mod_X(mul_X(res, base), C);
        }
        base = mod_X(mul_X(base, base), C);
        exp /= 2;
    }
    return res;
}

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(NULL);

    long long N;
    int M;
    if (!(cin >> N >> M >> K)) return 0;

    vector<vector<int>> C(11, vector<int>(K + 1, 0));
    for(int i = 0; i < M; ++i) {
        int d, p;
        cin >> d >> p;
        if (p <= K) {
            C[d][p] = (C[d][p] + 1) % MOD;
        }
    }

    vector<vector<int>> A(10, vector<int>(K + 1, 0));
    A[0][0] = 1;
    for (int i = 1; i < 10; ++i) {
        for (int d = 1; d <= i; ++d) {
            const auto& polyA = A[i-d];
            const auto& polyC = C[d];
            static unsigned long long tmp[405];
            memset(tmp, 0, sizeof(unsigned long long) * (K + 1));
            for (int x = 0; x <= K; ++x) {
                if (!polyA[x]) continue;
                unsigned long long ax = polyA[x];
                for (int y = 0; y <= K - x; ++y) {
                    tmp[x + y] += ax * polyC[y];
                }
                if (x % 8 == 7) {
                    for (int z = 0; z <= K; ++z) tmp[z] %= MOD;
                }
            }
            for (int z = 0; z <= K; ++z) {
                A[i][z] = (A[i][z] + tmp[z]) % MOD;
            }
        }
