model solution output:
### Main idea

To calculate the "happiness" of the list, we need to find the number of valid subsegments. A subsegment from day $i+1$ to $R$ is valid if the prefix sums $P_j \ge P_i$ for all $j \in [i+1, R]$. The maximum valid right bound for a start index $i+1$ is $NL[i] - 1$, where $NL[i]$ is the first index $j > i$ such that $P_j < P_i$.

Adding a glitch $X$ at day $k$ shifts all prefix sums $P_j$ for $j \ge k$ by $+X$. The change in happiness behaves fundamentally differently based on the sign of $X$:

1. **$X \ge 0$**: Prefix sums increase, so the failure point for any $i$ can only move further right. Specifically, the new failure point $Nxt[i]$ becomes the first $j > i$ where $P_j < P_i - X$, which is independent of $k$. We can simply use a difference array to add the constant improvement $Nxt[i] - NL[i]$ to all valid $k \in (i, NL[i]]$.
2. **$X < 0$**: Prefix sums decrease, so the failure point can shrink. As we sweep $k$ from right to left, the set of indices $i$ whose failure points are actively bounded by $k$ can be maintained. We use a Lazy Segment Tree over the compressed values of $P_i$ to dynamically track and range-update the new failure points for all currently active $i$.

### Technique used

Monotonic stack for initial failure points, binary lifting/segment tree for static queries ($X \ge 0$), and a Lazy Segment Tree with coordinate compression for dynamic range-updates during a right-to-left sweep ($X < 0$).

### Correctness argument

For $X \ge 0$, any $j \ge k$ failing the new condition implies $P_j < P_i - X \le P_i$. Since $j \ge NL[i]$, $Nxt[i]$ is invariant for all valid choices of $k$, allowing an $O(N)$ sweep with a difference array.
For $X < 0$, an index $i$ is "active" if its original failure hasn't happened yet ($NL[i] \ge k$). When sweeping $k$ right-to-left, an active index $i$ will have its new failure point snapped to $k$ exactly when $P_k < P_i + (-X)$. Because elements with the same $P_i$ become active concurrently, we can efficiently group them and use a Lazy Segment Tree to assign the new failure bound $k$ to all active elements satisfying $P_i > P_k + X$.

### Complexity analysis

* **Time Complexity:** - For $X \ge 0$: $O(N \log N)$ to find $Nxt[i]$ using a Segment Tree, followed by an $O(N)$ difference array sweep.
* For $X < 0$: $O(N \log N)$ to sort and coordinate compress $P_i$, and $O(N \log N)$ to perform range-updates and point-queries on the Lazy Segment Tree during the sweep.
Overall Time Complexity: $\mathcal{O}(N \log N)$.


* **Space/Memory Complexity:** $O(N)$ for the segment trees, monotonic stacks, and prefix sum arrays, comfortably fitting well within the 1024 MB limit.

### Complete C++20 implementation

```cpp
#include <iostream>
#include <vector>
#include <algorithm>

using namespace std;

long long tree_min_val[2000005];
void build_min_tree(int node, int L, int R, const vector<long long>& P) {
    if (L == R) {
        tree_min_val[node] = P[L];
        return;
    }
    int mid = L + (R - L) / 2;
    build_min_tree(2 * node, L, mid, P);
    build_min_tree(2 * node + 1, mid + 1, R, P);
    tree_min_val[node] = min(tree_min_val[2 * node], tree_min_val[2 * node + 1]);
}

int query_first(int node, int L, int R, int ql, int qr, long long val) {
    if (tree_min_val[node] >= val || L > qr || R < ql) return -1;
    if (L == R) return L;
    int mid = L + (R - L) / 2;
    int res = query_first(2 * node, L, mid, ql, qr, val);
    if (res != -1) return res;
    return query_first(2 * node + 1, mid + 1, R, ql, qr, val);
}

long long sum_tree[2000005];
int count_tree[2000005];
int lazy_tree[2000005];

void push_down(int node) {
    if (lazy_tree[node] != -1) {
        int k = lazy_tree[node];
        lazy_tree[2 * node] = k;
        sum_tree[2 * node] = 1LL * count_tree[2 * node] * k;
        lazy_tree[2 * node + 1] = k;
        sum_tree[2 * node + 1] = 1LL * count_tree[2 * node + 1] * k;
        lazy_tree[node] = -1;
    }
}

void add_active(int node, int L, int R, int idx, int c, int k) {
    if (L == R) {
        count_tree[node] += c;
        sum_tree[node] = 1LL * count_tree[node] * k;
        lazy_tree[node] = k;
        return;
    }
    push_down(node);
    int mid = L + (R - L) / 2;
    if (idx <= mid) add_active(2 * node, L, mid, idx, c, k);
    else add_active(2 * node + 1, mid + 1, R, idx, c, k);
    sum_tree[node] = sum_tree[2 * node] + sum_tree[2 * node + 1];
    count_tree[node] = count_tree[2 * node] + count_tree[2 * node + 1];
}

void remove_active(int node, int L, int R, int idx) {
    if (L == R) {
        count_tree[node] -= 1;
        if (count_tree[node] == 0) {
            sum_tree[node] = 0;
            lazy_tree[node] = -1;
        } else {
            sum_tree[node] = 1LL * count_tree[node] * lazy_tree[node];
        }
        return;
    }
    push_down(node);
    int mid = L + (R - L) / 2;
    if (idx <= mid) remove_active(2 * node, L, mid, idx);
    else remove_active(2 * node + 1, mid + 1, R, idx);
    sum_tree[node] = sum_tree[2 * node] + sum_tree[2 * node + 1];
    count_tree[node] = count_tree[2 * node] + count_tree[2 * node + 1];
}

void update_F(int node, int L, int R, int ql, int qr, int k) {
    if (ql <= L && R <= qr) {
        lazy_tree[node] = k;
        sum_tree[node] = 1LL * count_tree[node] * k;
        return;
    }
    push_down(node);
    int mid = L + (R - L) / 2;
    if (ql <= mid) update_F(2 * node, L, mid, ql, qr, k);
    if (qr > mid) update_F(2 * node + 1, mid + 1, R, ql, qr, k);
    sum_tree[node] = sum_tree[2 * node] + sum_tree[2 * node + 1];
}

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(NULL);

    long long X;
    int N;
    if (!(cin >> X >> N)) return 0;

    vector<long long> V(N + 1);
    vector<long long> P(N + 1, 0);
    for (int i = 1; i <= N; ++i) {
        cin >> V[i];
        P[i] = P[i - 1] + V[i];
    }

    vector<int> NL(N + 1, N + 1);
    vector<int> st;
    for (int i = 0; i <= N; ++i) {
        while (!st.empty() && P[i] < P[st.back()]) {
            NL[st.back()] = i;
            st.pop_back();
        }
        st.push_back(i);
    }

    long long max_H = 0;

    if (X >= 0) {
        build_min_tree(1, 0, N, P);
        vector<long long> diff(N + 2, 0);
        long long orig_H_sum = 0;

        for (int i = 0; i < N; ++i) {
            long long orig = NL[i] - 1 - i;
            orig_H_sum += orig;
            int nxt = query_first(1, 0, N, i + 1, N, P[i] - X);
            if (nxt == -1) nxt = N + 1;

            long long delta = nxt - NL[i];
            if (delta > 0) {
                diff[i + 1] += delta;
                diff[min((int)N + 1, NL[i] + 1)] -= delta;
            }
        }

        long long cur_diff = 0;
        for (int k = 1; k <= N; ++k) {
            cur_diff += diff[k];
            max_H = max(max_H, orig_H_sum + cur_diff);
        }
    } else {
        vector<long long> vals;
        for (int i = 0; i <= N; ++i) vals.push_back(P[i]);
        sort(vals.begin(), vals.end());
        vals.erase(unique(vals.begin(), vals.end()), vals.end());
        int V_size = vals.size();

        auto get_idx = [&](long long p) {
            return lower_bound(vals.begin(), vals.end(), p) - vals.begin() + 1;
        };

        for (int i = 0; i < 4 * V_size + 5; ++i) {
            lazy_tree[i] = -1;
            sum_tree[i] = 0;
            count_tree[i] = 0;
        }

        vector<vector<int>> add_at(N + 2);
        long long base_sum = 0;
        vector<long long> base_val(N + 2, 0);
        vector<long long> sum_NL(N + 2, 0);

        for (int i = 0; i < N; ++i) {
            add_at[NL[i]].push_back(i);
            if (NL[i] <= N) sum_NL[NL[i]] += NL[i];
        }

        for (int k = 1; k <= N; ++k) {
            base_sum += sum_NL[k - 1];
            base_val[k] = base_sum;
        }

        vector<long long> orig_H(N);
        vector<long long> suf_orig_H(N + 1, 0);
        for (int i = N - 1; i >= 0; --i) {
            orig_H[i] = NL[i] - 1 - i;
            suf_orig_H[i] = orig_H[i] + suf_orig_H[i + 1];
        }

        for (int k = N + 1; k >= 1; --k) {
            if (k < N) remove_active(1, 1, V_size, get_idx(P[k]));

            for (int i : add_at[k]) {
                add_active(1, 1, V_size, get_idx(P[i]), 1, k);
            }

            if (k <= N) {
                long long threshold = P[k] + X;
                int ql = upper_bound(vals.begin(), vals.end(), threshold) - vals.begin() + 1;
                int qr = V_size;
                if (ql <= qr) update_F(1, 1, V_size, ql, qr, k);

                long long W = sum_tree[1];
                long long sum_1_plus_i = 1LL * k * (k + 1) / 2;
                long long H_k = base_val[k] + W - sum_1_plus_i + suf_orig_H[k];
                max_H = max(max_H, H_k);
            }
        }
    }

    cout << max_H << "\n";
    return 0;
}

