            if (k < N) remove_active(1, 1, V_size, get_idx(P[k]));
            
            for (int i : add_at[k]) {
                add_active(1, 1, V_size, get_idx(P[i]), 1, k);
            }

            if (k <= N) {
                long long threshold = P[k] + X;
                int ql = upper_bound(vals.begin(), vals.end(), threshold) - vals.begin() + 1;
                int qr = V_size;
                if (ql <= qr) update_F(1, 1, V_size, ql, qr, k);

                long long W = sum_tree[1];
                long long sum_1_plus_i = 1LL * k * (k + 1) / 2;
                long long H_k = base_val[k] + W - sum_1_plus_i + suf_orig_H[k];
                max_H = max(max_H, H_k);
            }
        }
    }

    cout << max_H << "\n";
    return 0;
}

model solution output:
### Main idea

The problem asks for the minimum time to travel between two points on a grid while avoiding moving clouds. The core insight is that since the cyclist is safe when stopped at integer coordinates (points of interest), we only need to verify if the cyclist intersects the strict interior of any cloud during the open time interval $(t, t+1)$ while moving between adjacent grid points.

Because clouds are rectilinear polygons moving at a constant speed, the movement of the cyclist relative to the cloud is always a straight line segment connecting two integer coordinates. We can rasterize each cloud into a boolean grid of $1 \times 1$ cells. Checking whether a line segment passes through the strict interior of the cloud then reduces to simple logical checks on the cells immediately surrounding the segment. To find the fastest path, we can explore the 3D state space `(x, y, t)` using Breadth-First Search (BFS).

### Technique used

* **Breadth-First Search (BFS)** on a 3D state space `(x, y, t)` to find the unweighted shortest path.
* **Scanline Polygon Filling** to convert the bounding vertices of orthogonal polygons into a 2D grid of filled cells.
* **Relative Coordinate Geometry** to evaluate collision-free movement dynamically.

### Correctness argument

1. **State Space Bound**: Clouds are initially confined to $[0, 100] \times [0, 100]$ and move 1 unit per time. A coordinate expansion padded by 30 units (i.e., $[-30, 130]$) is sufficient to maneuver around any cloud formation. By $t = 200$, all clouds will have entirely drifted past the grid and destination. After $t = 200$, the area is completely unobstructed, and the remaining travel time is exactly the Manhattan distance to the destination.
2. **Safety Invariant**: A cyclist is fully protected at integer coordinates while stopped. When transitioning from $(ux, uy)$ to $(vx, vy)$, the relative movement vector $V = (v - u) - D_{cloud}$ uniquely dictates which edges and cells the cyclist traverses relative to the cloud. By checking if the cells bounding these paths are strictly inside the cloud, we robustly detect if the cyclist ever enters the cloud's interior, making the safety verification exact and continuous.
3. **Bounding Box Optimization**: We dynamically check if the cyclist's movement bounding box intersects the cloud's sweeping bounding box during $(t, t+1)$. If they do not overlap, we skip the exact intersection tests, massively reducing constant overhead.

### Complexity analysis

* **Time Complexity:** $\mathcal{O}(X \cdot Y \cdot T \cdot \text{avg\_cloud\_overlaps} + N \cdot V \log V)$, where $X, Y \le 160$ are the grid dimensions, $T \le 200$ is the time limit before reverting to Manhattan distance, $N$ is the number of clouds, and $V$ is the number of vertices. The state space contains at most $160 \times 160 \times 200 \approx 5.1 \times 10^6$ states. With the bounding box pre-filter, the collision logic executes in $\mathcal{O}(1)$ on average, making the BFS comfortably run well under the 3.5 seconds limit.
* **Memory/Space Complexity:** $\mathcal{O}(X \cdot Y \cdot T)$ to store the BFS visited array, and $\mathcal{O}(N \cdot W \cdot H)$ for the rasterized clouds. The total memory used is roughly $5.5\text{ MB}$, well within the 1024 MB limit.

### Complete C++20 implementation

```cpp
#include <iostream>
#include <vector>
#include <queue>
#include <tuple>
#include <algorithm>
#include <cmath>
#include <cstring>

using namespace std;

struct Cloud {
    int dx, dy;
    int min_x, max_x, min_y, max_y;
    bool cell_in[105][105];

    Cloud() : min_x(1000), max_x(-1000), min_y(1000), max_y(-1000) {
        memset(cell_in, 0, sizeof(cell_in));
        dx = dy = 0;
    }

    bool has_cell(int cx, int cy) const {
        if (cx < 0 || cx > 100 || cy < 0 || cy > 100) return false;
        return cell_in[cx][cy];
    }

    bool safe_cell(int cx, int cy) const { return !has_cell(cx, cy); }
    bool safe_H_edge(int x, int y) const { return !(has_cell(x, y) && has_cell(x, y - 1)); }
    bool safe_V_edge(int x, int y) const { return !(has_cell(x, y) && has_cell(x - 1, y)); }
    bool safe_point(int x, int y) const { 
        return !(has_cell(x, y) && has_cell(x - 1, y) && has_cell(x, y - 1) && has_cell(x - 1, y - 1)); 
    }

    bool is_safe_from(int ux, int uy, int vx, int vy, int t) const {
        if (ux == vx && uy == vy) return true;

        int c_min_x = min(ux, vx), c_max_x = max(ux, vx);
        int c_min_y = min(uy, vy), c_max_y = max(uy, vy);

        int bb_min_x = min_x + min(t * dx, (t + 1) * dx);
        int bb_max_x = max_x + max(t * dx, (t + 1) * dx);
        int bb_min_y = min_y + min(t * dy, (t + 1) * dy);
        int bb_max_y = max_y + max(t * dy, (t + 1) * dy);

        if (c_max_x < bb_min_x || c_min_x > bb_max_x || c_max_y < bb_min_y || c_min_y > bb_max_y) {
            return true;
        }

        int Ax = ux - t * dx, Ay = uy - t * dy;
        int Bx = vx - (t + 1) * dx, By = vy - (t + 1) * dy;
        int Vx = Bx - Ax, Vy = By - Ay;

        if (Vx == 0 && Vy == 0) return safe_point(Ax, Ay);
        if (Vx == 1 && Vy == 1) return safe_cell(Ax, Ay);
        if (Vx == 1 && Vy == -1) return safe_cell(Ax, Ay - 1);
        if (Vx == -1 && Vy == 1) return safe_cell(Ax - 1, Ay);
        if (Vx == -1 && Vy == -1) return safe_cell(Ax - 1, Ay - 1);

        if (Vx == 1 && Vy == 0) return safe_H_edge(Ax, Ay);
        if (Vx == -1 && Vy == 0) return safe_H_edge(Ax - 1, Ay);
        if (Vx == 0 && Vy == 1) return safe_V_edge(Ax, Ay);
        if (Vx == 0 && Vy == -1) return safe_V_edge(Ax, Ay - 1);

        if (Vx == 2 && Vy == 0) return safe_H_edge(Ax, Ay) && safe_H_edge(Ax + 1, Ay);
        if (Vx == -2 && Vy == 0) return safe_H_edge(Ax - 1, Ay) && safe_H_edge(Ax - 2, Ay);
        if (Vx == 0 && Vy == 2) return safe_V_edge(Ax, Ay) && safe_V_edge(Ax, Ay + 1);
        if (Vx == 0 && Vy == -2) return safe_V_edge(Ax, Ay - 1) && safe_V_edge(Ax, Ay - 2);

        return false;
    }
};

bool vis[165][165][205];
vector<Cloud> clouds;

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(NULL);

    int Xo, Yo, Xd, Yd;
    if (!(cin >> Xo >> Yo >> Xd >> Yd)) return 0;

    if (Xo == Xd && Yo == Yd) {
        cout << 0 << "\n";
        return 0;
    }

    int N;
    cin >> N;
    clouds.resize(N);

    for (int c = 0; c < N; ++c) {
        char dir;
        int V_cnt;
        cin >> dir >> V_cnt;

        if (dir == 'N') { clouds[c].dx = 0; clouds[c].dy = 1; }
        else if (dir == 'S') { clouds[c].dx = 0; clouds[c].dy = -1; }
        else if (dir == 'E') { clouds[c].dx = 1; clouds[c].dy = 0; }
        else if (dir == 'W') { clouds[c].dx = -1; clouds[c].dy = 0; }

        vector<pair<int, int>> pts(V_cnt);
        for (int i = 0; i < V_cnt; ++i) {
            cin >> pts[i].first >> pts[i].second;
            clouds[c].min_x = min(clouds[c].min_x, pts[i].first);
            clouds[c].max_x = max(clouds[c].max_x, pts[i].first);
            clouds[c].min_y = min(clouds[c].min_y, pts[i].second);
            clouds[c].max_y = max(clouds[c].max_y, pts[i].second);
        }

        for (int cy = 0; cy <= 100; ++cy) {
            vector<int> inters;
            for (int i = 0; i < V_cnt; ++i) {
                auto p1 = pts[i];
                auto p2 = pts[(i + 1) % V_cnt];
                if (p1.first == p2.first) {
                    int mn_y = min(p1.second, p2.second);
                    int mx_y = max(p1.second, p2.second);
                    if (cy >= mn_y && cy < mx_y) inters.push_back(p1.first);
                }
            }
            sort(inters.begin(), inters.end());
            for (size_t i = 0; i + 1 < inters.size(); i += 2) {
                for (int cx = inters[i]; cx < inters[i + 1]; ++cx) {
                    if (cx >= 0 && cx <= 100 && cy >= 0 && cy <= 100) {
                        clouds[c].cell_in[cx][cy] = true;
                    }
                }
            }
        }
    }

    auto get_idx = [](int x) { return x + 30; };

    queue<tuple<int, int, int>> q;
    q.push({Xo, Yo, 0});
    vis[get_idx(Xo)][get_idx(Yo)][0] = true;

    int ans = 2e9;
    int dx_arr[] = {0, 1, -1, 0, 0};
    int dy_arr[] = {0, 0, 0, 1, -1};

    while (!q.empty()) {
        auto [x, y, t] = q.front();
        q.pop();

        if (x == Xd && y == Yd) {
            cout << t << "\n";
            return 0;
        }

        if (t == 200) {
            ans = min(ans, 200 + abs(Xd - x) + abs(Yd - y));
            continue;
        }

        for (int i = 0; i < 5; ++i) {
            int nx = x + dx_arr[i];
            int ny = y + dy_arr[i];

            if (nx < -30 || nx > 130 || ny < -30 || ny > 130) continue;

            if (!vis[get_idx(nx)][get_idx(ny)][t + 1]) {
                bool safe = true;
                for (const auto& cloud : clouds) {
                    if (!cloud.is_safe_from(x, y, nx, ny, t)) {
                        safe = false;
                        break;
                    }
                }
                if (safe) {
                    vis[get_idx(nx)][get_idx(ny)][t + 1] = true;
                    q.push({nx, ny, t + 1});
                }
            }
        }
    }

    cout << ans << "\n";
    return 0;
}

