model solution output:
### Main idea

The problem asks us to determine for each tree $T$ how many other trees in the input collection can "generate" it. A tree $T_{generator}$ generates $T$ if $T$ can be partitioned into connected components that are all isomorphic to $T_{generator}$.

A key property of trees is that for any integer $C$ that divides $|V(T)|$, there is at most **one** valid way to partition $T$ into connected components of size exactly $C$. If we root $T$ arbitrarily, the only edges we are allowed to cut to form such components are exactly those where the size of the descending subtree is a multiple of $C$.

We can evaluate all candidate generator sizes $C$ that actually exist in the input collection and divide $|V(T)|$. For each candidate $C$, we count how many valid edges can be cut. If this count is exactly $|V(T)| / C - 1$, the tree $T$ can be decomposed into size-$C$ components. We then extract these components, compute a robust canonical hash for each, and verify that they are identical to each other. Finally, we add the number of matching input trees to our answer.

### Technique used

* **Tree Hashing & Isomorphism**: Using a center-rooted iterative polynomial hash with `splitmix64` to establish a unique canonical representation for any tree.
* **Tree Decomposition (Greedy Cuts)**: Using subtree sizes to deterministically identify the only possible edges to cut when partitioning a tree into components of size $C$.

### Correctness argument

Let $S_u$ be the size of the subtree rooted at $u$. If we cut an edge $(u, \text{parent}(u))$, the tree is split into two components. In order for all final connected components to have a size of exactly $C$, the size of the component completely contained within the subtree of $u$ must be a multiple of $C$. Hence, $S_u \equiv 0 \pmod C$ is a strict requirement for every cut edge.
Since partitioning a tree of size $K$ into components of size $C$ requires exactly $K / C - 1$ cuts, we only need to verify if exactly $K / C - 1$ edges satisfy this modular property. If they do, the resulting components are mathematically guaranteed to have a size of exactly $C$. Extracting these components and hashing them canonicalizes their structure, allowing us to accurately check isomorphism among the pieces and against the input collection.

### Complexity analysis

* **Time Complexity:** Computing sizes and hashes for the original trees takes $O(\sum K \log K)$. Testing a divisor $C$ takes $O(K)$ to verify cuts. If the cuts match, extracting and hashing the components takes $O(K \log C)$. Over all candidates, this amounts to $O(\sum K \log K \cdot d_{valid})$ where $d_{valid}$ is the small number of valid divisors that perfectly partition the tree. The overall time falls well within the generous $5.0$ seconds limit.
* **Memory Complexity:** $O(\sum K)$ for storing adjacency lists, subgraph component arrays, and global maps. Bounded comfortably within $1024 \text{ MB}$.

### Complete C++20 implementation

```cpp
#include <iostream>
#include <vector>
#include <algorithm>
#include <chrono>
#include <unordered_map>

using namespace std;

struct custom_hash {
    static uint64_t splitmix64(uint64_t x) {
        x += 0x9e3779b97f4a7c15;
        x = (x ^ (x >> 30)) * 0xbf58476d1ce4e5b9;
        x = (x ^ (x >> 27)) * 0x94d049bb133111eb;
        return x ^ (x >> 31);
    }
    size_t operator()(uint64_t x) const {
        static const uint64_t FIXED_RANDOM = 19937011; 
        return splitmix64(x + FIXED_RANDOM);
    }
};

uint64_t get_rooted_hash_iterative(int root, const vector<vector<int>>& tree_adj) {
    int n = tree_adj.size();
    vector<int> parent(n, -1);
    vector<int> order;
    order.reserve(n);
    vector<int> q;
    q.push_back(root);
    order.push_back(root);
    int head = 0;

    while(head < (int)q.size()) {
        int u = q[head++];
        for(int v : tree_adj[u]) {
            if (v != parent[u]) {
                parent[v] = u;
                q.push_back(v);
                order.push_back(v);
            }
        }
    }

    vector<uint64_t> dp(n, 0);
    for(int i = n - 1; i >= 0; --i) {
        int u = order[i];
        vector<uint64_t> child_hashes;
        for(int v : tree_adj[u]) {
            if (v != parent[u]) {
                child_hashes.push_back(dp[v]);
            }
        }
        sort(child_hashes.begin(), child_hashes.end());
        uint64_t h = 0x123456789abcdef;
        for(uint64_t ch : child_hashes) {
            h ^= custom_hash::splitmix64(ch) + 0x9e3779b97f4a7c15 + (h << 6) + (h >> 2);
        }
        dp[u] = h;
    }
    return dp[root];
}

uint64_t get_canonical_hash(const vector<vector<int>>& tree_adj) {
    int n = tree_adj.size();
    if (n == 1) {
        uint64_t h = get_rooted_hash_iterative(0, tree_adj);
        return h ^ custom_hash::splitmix64(n + 0x1234567);
    }

    vector<int> deg(n);
    vector<int> leaves;
    for(int i = 0; i < n; ++i) {
        deg[i] = tree_adj[i].size();
        if(deg[i] <= 1) leaves.push_back(i);
    }

    int rem = n;
    while(rem > 2) {
        vector<int> next_leaves;
        for(int u : leaves) {
            rem--;
            for(int v : tree_adj[u]) {
                if(--deg[v] == 1) {
                    next_leaves.push_back(v);
                }
            }
        }
        leaves = next_leaves;
    }

    uint64_t final_h = 0;
    if (leaves.size() == 1) {
        final_h = get_rooted_hash_iterative(leaves[0], tree_adj);
    } else {
        uint64_t h1 = get_rooted_hash_iterative(leaves[0], tree_adj);
        uint64_t h2 = get_rooted_hash_iterative(leaves[1], tree_adj);
        final_h = min(h1, h2);
    }
    return final_h ^ custom_hash::splitmix64(n + 0x1234567);
}

struct Tree {
    int K;
    vector<vector<int>> adj;
    vector<int> parent;
    vector<int> S;
    uint64_t hash;
};

void build_sizes(Tree& t) {
    int n = t.K;
    t.parent.assign(n, -1);
    t.S.assign(n, 1);
    vector<int> order;
    order.reserve(n);
    vector<int> q;
    q.push_back(0);
    order.push_back(0);
    int head = 0;

    while(head < (int)q.size()) {
        int u = q[head++];
        for(int v : t.adj[u]) {
            if (v != t.parent[u]) {
                t.parent[v] = u;
                q.push_back(v);
                order.push_back(v);
            }
        }
    }
    for(int i = n - 1; i >= 0; --i) {
        int u = order[i];
        if (t.parent[u] != -1) {
            t.S[t.parent[u]] += t.S[u];
        }
    }
}

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(NULL);

    int N;
    if (!(cin >> N)) return 0;

    vector<Tree> trees(N);
    unordered_map<uint64_t, int, custom_hash> global_hash_count;
    vector<bool> has_size(400005, false);

    for(int i = 0; i < N; ++i) {
        cin >> trees[i].K;
        trees[i].adj.resize(trees[i].K);
        for(int j = 0; j < trees[i].K - 1; ++j) {
            int u, v; 
            cin >> u >> v; 
            --u; --v;
            trees[i].adj[u].push_back(v);
            trees[i].adj[v].push_back(u);
        }
        build_sizes(trees[i]);
        trees[i].hash = get_canonical_hash(trees[i].adj);
        global_hash_count[trees[i].hash]++;
        has_size[trees[i].K] = true;
    }

    vector<int> local_idx(400005, -1);
    vector<int> comp_nodes;
    comp_nodes.reserve(400005);

    for(int i = 0; i < N; ++i) {
        int ans = 0;
        int K = trees[i].K;

        for(int C = 1; C <= K; ++C) {
            if (K % C == 0 && has_size[C]) {
                if (C == K) {
                    ans += global_hash_count[trees[i].hash] - 1;
                } else {
                    int cuts = 0;
                    for(int j = 1; j < K; ++j) {
                        if (trees[i].S[j] % C == 0) cuts++;
                    }

                    if (cuts == K / C - 1) {
                        bool ok = true;
                        uint64_t target_hash = 0;
                        vector<bool> vis(K, false);

                        for(int j = 0; j < K; ++j) {
                            if (!vis[j]) {
                                comp_nodes.clear();
                                comp_nodes.push_back(j);
                                vis[j] = true;
                                int head = 0;

                                while(head < (int)comp_nodes.size()) {
                                    int u = comp_nodes[head++];
                                    for(int v : trees[i].adj[u]) {
                                        if (vis[v]) continue;
                                        bool is_cut = false;
                                        if (trees[i].parent[u] == v) is_cut = (trees[i].S[u] % C == 0);
                                        else if (trees[i].parent[v] == u) is_cut = (trees[i].S[v] % C == 0);

                                        if (!is_cut) {
                                            vis[v] = true;
                                            comp_nodes.push_back(v);
                                        }
                                    }
                                }

                                if ((int)comp_nodes.size() != C) {
                                    ok = false; 
                                    break;
                                }

                                vector<vector<int>> local_adj(C);
                                for(int k = 0; k < C; ++k) local_idx[comp_nodes[k]] = k;
                                for(int u : comp_nodes) {
                                    for(int v : trees[i].adj[u]) {
                                        if (local_idx[v] != -1) {
                                            local_adj[local_idx[u]].push_back(local_idx[v]);
                                        }
                                    }
                                }
                                for(int k = 0; k < C; ++k) local_idx[comp_nodes[k]] = -1;

                                uint64_t h = get_canonical_hash(local_adj);

                                if (target_hash == 0) {
                                    if (global_hash_count.find(h) == global_hash_count.end()) {
                                        ok = false; 
                                        break;
                                    }
                                    target_hash = h;
                                } else {
                                    if (h != target_hash) {
                                        ok = false; 
                                        break;
                                    }
                                }
                            }
                        }
                        if (ok) {
                            ans += global_hash_count[target_hash];
                        }
                    }
                }
            }
        }
        cout << ans << (i == N - 1 ? "" : " ");
    }
    cout << "\n";
    return 0;
}

