};

uint64_t get_rooted_hash_iterative(int root, const vector<vector<int>>& tree_adj) {
    int n = tree_adj.size();
    vector<int> parent(n, -1);
    vector<int> order;
    order.reserve(n);
    vector<int> q;
    q.push_back(root);
    order.push_back(root);
    int head = 0;
    
    while(head < (int)q.size()) {
        int u = q[head++];
        for(int v : tree_adj[u]) {
            if (v != parent[u]) {
                parent[v] = u;
                q.push_back(v);
                order.push_back(v);
            }
        }
    }
    
    vector<uint64_t> dp(n, 0);
    for(int i = n - 1; i >= 0; --i) {
        int u = order[i];
        vector<uint64_t> child_hashes;
        for(int v : tree_adj[u]) {
            if (v != parent[u]) {
                child_hashes.push_back(dp[v]);
            }
        }
        sort(child_hashes.begin(), child_hashes.end());
        uint64_t h = 0x123456789abcdef;
        for(uint64_t ch : child_hashes) {
            h ^= custom_hash::splitmix64(ch) + 0x9e3779b97f4a7c15 + (h << 6) + (h >> 2);
        }
        dp[u] = h;
    }
    return dp[root];
}

uint64_t get_canonical_hash(const vector<vector<int>>& tree_adj) {
    int n = tree_adj.size();
    if (n == 1) {
        uint64_t h = get_rooted_hash_iterative(0, tree_adj);
        return h ^ custom_hash::splitmix64(n + 0x1234567);
    }
    
    vector<int> deg(n);
    vector<int> leaves;
    for(int i = 0; i < n; ++i) {
        deg[i] = tree_adj[i].size();
        if(deg[i] <= 1) leaves.push_back(i);
    }
    
    int rem = n;
    while(rem > 2) {
        vector<int> next_leaves;
        for(int u : leaves) {
            rem--;
            for(int v : tree_adj[u]) {
                if(--deg[v] == 1) {
                    next_leaves.push_back(v);
                }
            }
        }
        leaves = next_leaves;
    }
    
    uint64_t final_h = 0;
    if (leaves.size() == 1) {
        final_h = get_rooted_hash_iterative(leaves[0], tree_adj);
    } else {
        uint64_t h1 = get_rooted_hash_iterative(leaves[0], tree_adj);
        uint64_t h2 = get_rooted_hash_iterative(leaves[1], tree_adj);
        final_h = min(h1, h2);
    }
    return final_h ^ custom_hash::splitmix64(n + 0x1234567);
}

struct Tree {
    int K;
    vector<vector<int>> adj;
    vector<int> parent;
    vector<int> S;
    uint64_t hash;
};

void build_sizes(Tree& t) {
    int n = t.K;
    t.parent.assign(n, -1);
    t.S.assign(n, 1);
    vector<int> order;
    order.reserve(n);
    vector<int> q;
    q.push_back(0);
    order.push_back(0);
    int head = 0;
    
    while(head < (int)q.size()) {
        int u = q[head++];
        for(int v : t.adj[u]) {
            if (v != t.parent[u]) {
                t.parent[v] = u;
                q.push_back(v);
                order.push_back(v);
            }
        }
    }
    for(int i = n - 1; i >= 0; --i) {
        int u = order[i];
        if (t.parent[u] != -1) {
            t.S[t.parent[u]] += t.S[u];
        }
    }
}

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(NULL);

    int N;
    if (!(cin >> N)) return 0;
    
    vector<Tree> trees(N);
    unordered_map<uint64_t, int, custom_hash> global_hash_count;
    vector<bool> has_size(400005, false);

    for(int i = 0; i < N; ++i) {
        cin >> trees[i].K;
        trees[i].adj.resize(trees[i].K);
        for(int j = 0; j < trees[i].K - 1; ++j) {
            int u, v; 
            cin >> u >> v; 
            --u; --v;
            trees[i].adj[u].push_back(v);
            trees[i].adj[v].push_back(u);
        }
        build_sizes(trees[i]);
        trees[i].hash = get_canonical_hash(trees[i].adj);
        global_hash_count[trees[i].hash]++;
        has_size[trees[i].K] = true;
    }

    vector<int> local_idx(400005, -1);
    vector<int> comp_nodes;
    comp_nodes.reserve(400005);

    for(int i = 0; i < N; ++i) {
        int ans = 0;
        int K = trees[i].K;
        
        for(int C = 1; C <= K; ++C) {
            if (K % C == 0 && has_size[C]) {
                if (C == K) {
                    ans += global_hash_count[trees[i].hash] - 1;
                } else {
                    int cuts = 0;
                    for(int j = 1; j < K; ++j) {
                        if (trees[i].S[j] % C == 0) cuts++;
                    }
                    
                    if (cuts == K / C - 1) {
                        bool ok = true;
                        uint64_t target_hash = 0;
                        vector<bool> vis(K, false);
                        
                        for(int j = 0; j < K; ++j) {
                            if (!vis[j]) {
                                comp_nodes.clear();
                                comp_nodes.push_back(j);
                                vis[j] = true;
                                int head = 0;
                                
                                while(head < (int)comp_nodes.size()) {
                                    int u = comp_nodes[head++];
                                    for(int v : trees[i].adj[u]) {
                                        if (vis[v]) continue;
                                        bool is_cut = false;
                                        if (trees[i].parent[u] == v) is_cut = (trees[i].S[u] % C == 0);
                                        else if (trees[i].parent[v] == u) is_cut = (trees[i].S[v] % C == 0);
                                        
                                        if (!is_cut) {
                                            vis[v] = true;
                                            comp_nodes.push_back(v);
                                        }
                                    }
                                }
                                
                                if ((int)comp_nodes.size() != C) {
                                    ok = false; 
                                    break;
                                }
                                
                                vector<vector<int>> local_adj(C);
                                for(int k = 0; k < C; ++k) local_idx[comp_nodes[k]] = k;
                                for(int u : comp_nodes) {
                                    for(int v : trees[i].adj[u]) {
                                        if (local_idx[v] != -1) {
                                            local_adj[local_idx[u]].push_back(local_idx[v]);
                                        }
                                    }
                                }
                                for(int k = 0; k < C; ++k) local_idx[comp_nodes[k]] = -1;
                                
                                uint64_t h = get_canonical_hash(local_adj);
                                
                                if (target_hash == 0) {
                                    if (global_hash_count.find(h) == global_hash_count.end()) {
                                        ok = false; 
                                        break;
                                    }
                                    target_hash = h;
                                } else {
                                    if (h != target_hash) {
                                        ok = false; 
                                        break;
                                    }
                                }
                            }
                        }
                        if (ok) {
                            ans += global_hash_count[target_hash];
                        }
                    }
                }
            }
        }
        cout << ans << (i == N - 1 ? "" : " ");
    }
    cout << "\n";
    return 0;
}

model solution output:
### Main idea

The problem asks for the number of valid ways to complete a string of digits, given a set of known characters and multiple constraints specifying that certain substrings must be palindromes. A palindrome constraint means that the characters in the substring are symmetric. This establishes an equivalence relation among the positions of the string. The total number of valid configurations is $2^K \pmod{10^9+7}$, where $K$ is the number of independent equivalence components that contain no known '0' or '1' characters. If any component contains both a '0' and a '1', there is a contradiction and the answer is 0.

To avoid processing potentially $O(N^2)$ equality constraints natively, we can treat the palindromic conditions as constraints equating a substring to its reversed counterpart. This allows us to apply a Sparse Table / Disjoint Set Union (DSU) optimization over intervals, a technique commonly used to answer equality queries on static strings.

### Technique used

**Disjoint Set Union (DSU) on Strings (Sparse Table trick)** We maintain an array of DSUs where $DSU[k]$ handles equivalences between substrings of length $2^k$. For each $k$, we maintain two types of nodes for each starting index $i$:

1. Forward string $F(i)$ representing $s[i \dots i+2^k-1]$
2. Reversed string $R(i)$ representing the reverse of $s[i \dots i+2^k-1]$

When an interval is declared a palindrome, we find the largest power of 2, $2^k$, that fits in the interval length. We can cover the palindrome condition by equating its prefix of length $2^k$ to the reverse of its suffix of length $2^k$, and similarly for its suffix and the reverse of its prefix.

After all intervals are logged at their appropriate log-levels, we push these constraints down from level $k$ to $k-1$. If two blocks of length $2^k$ are equated, their corresponding left and right sub-blocks of length $2^{k-1}$ must also be equated. At level 0, we can read the equivalences between single characters directly.

### Correctness argument

Any substring of length $L$ can be covered by two possibly overlapping blocks of length $2^k$, where $2^k \le L \le 2^{k+1}$. Enforcing $A = rev(B)$ at level $k$ accurately enforces the property that every corresponding character in $A$ and $rev(B)$ must match.

By pushing equivalences from $k$ down to $k-1$, we maintain all transitive dependencies without redundant calculations. Because $rev(L \cdot R) = rev(R) \cdot rev(L)$, the left sub-block of a reversed string corresponds to the right sub-block of the forward string. The downward propagation perfectly unrolls this mapping until we reach base characters at length $1$ (level $0$). A string of length $1$ is inherently identical to its reverse, so we merge the forward and reversed state of each character at level $0$, leaving us with an exact set of character-level connected components.

### Complexity analysis

* **Time Complexity:** $O(N \log N + M \alpha(N))$. Initializing the DSUs and pushing the constraints down takes $O(N)$ operations for each of the $\log_2 N$ levels. Inside each operation, DSU `find` and `merge` take amortized $O(\alpha(N))$ which behaves as $O(1)$. Thus, processing the structure takes heavily bounded $O(N \log N)$ time.
* **Memory Complexity:** $O(N \log N)$. Maintaining a parent array of size $2N$ across $\approx 19$ levels (for $N \le 300,000$) requires about $45 \text{ MB}$ of memory, safely well within the generous $1024 \text{ MB}$ limit.

### Complete C++20 implementation

```cpp
#include <iostream>
#include <vector>
#include <string>

using namespace std;

const int MOD = 1e9 + 7;

int parent_dsu[20][600005];

int find_set(int k, int i) {
    if (parent_dsu[k][i] == i) return i;
    return parent_dsu[k][i] = find_set(k, parent_dsu[k][i]);
}

void merge_set(int k, int u, int v, int n) {
    int pu = find_set(k, u);
    int pv = find_set(k, v);
    if (pu != pv) {
        parent_dsu[k][pu] = pv;
    }
    int su = u < n ? u + n : u - n;
    int sv = v < n ? v + n : v - n;
    int psu = find_set(k, su);
    int psv = find_set(k, sv);
    if (psu != psv) {
        parent_dsu[k][psu] = psv;
    }
}

int L(int x, int k, int n) {
    if (x < n) return x;
    return x + (1 << (k - 1));
}

int R(int x, int k, int n) {
    if (x < n) return x + (1 << (k - 1));
    return x;
}

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(NULL);

    int n, m;
    if (!(cin >> n >> m)) return 0;

    string s;
    cin >> s;

    int max_k = 31 - __builtin_clz(n);

    for (int k = 0; k <= max_k; k++) {
        for (int i = 0; i < 2 * n; i++) {
            parent_dsu[k][i] = i;
        }
    }

    for (int i = 0; i < m; i++) {
        int l, r;
        cin >> l >> r;
        l--; r--;

        int len = r - l + 1;
        int k = 31 - __builtin_clz(len);

        merge_set(k, l, (r - (1 << k) + 1) + n, n);
        merge_set(k, r - (1 << k) + 1, l + n, n);
    }

    for (int k = max_k; k >= 1; k--) {
        for (int i = 0; i < 2 * n; i++) {
            int p = find_set(k, i);
            if (i != p) {
                merge_set(k - 1, L(i, k, n), L(p, k, n), n);
                merge_set(k - 1, R(i, k, n), R(p, k, n), n);
            }
        }
    }

    for (int i = 0; i < n; i++) {
        merge_set(0, i, i + n, n);
    }

    vector<char> comp_val(2 * n, '?');
    bool possible = true;

    for (int i = 0; i < n; i++) {
        if (s[i] != '?') {
            int p = find_set(0, i);
            if (comp_val[p] != '?' && comp_val[p] != s[i]) {
                possible = false;
                break;
            }
            comp_val[p] = s[i];
        }
    }

    if (!possible) {
        cout << 0 << "\n";
        return 0;
    }

    int free_comps = 0;
    vector<bool> visited(2 * n, false);
    for (int i = 0; i < n; i++) {
        int p = find_set(0, i);
        if (!visited[p]) {
            visited[p] = true;
            if (comp_val[p] == '?') {
                free_comps++;
            }
        }
    }

    long long ans = 1;
    for (int i = 0; i < free_comps; i++) {
        ans = (ans * 2) % MOD;
    }

    cout << ans << "\n";
    return 0;
}

