model solution output:
### Main idea

A concatenation of two teams is formed by joining a team $A_i$ from university A with a team $B_j$ from university B. A team is considered non-peculiar if every concatenation involving it can also be formed by some other pair of teams; otherwise, it is peculiar.

A collision between two different concatenations $A_i + B_j = A_k + B_l$ (where $A_i \neq A_k$ and $B_j \neq B_l$) means none of these four teams uniquely produce this concatenation. Assuming without loss of generality that $|A_i| < |A_k|$, $A_i$ must be a proper prefix of $A_k$. Therefore, there must exist some non-empty string $S$ such that $A_k = A_i + S$.
Substituting this into the concatenation equation gives $A_i + B_j = A_i + S + B_l$, which simplifies to $B_j = S + B_l$.

This reveals that any collision is perfectly characterized by a non-empty string $S$ which acts simultaneously as a proper suffix for some team in A (with the prefix also being a valid team in A) and as a proper prefix for some team in B (with the suffix also being a valid team in B). By identifying all such strings $S$ generated by valid pairs in A and valid pairs in B, we can intersect these two sets. Any team involved in creating an $S$ present in both sets participates in a collision and is therefore non-peculiar.

### Technique used

**Tries (Prefix Trees) and Polynomial String Hashing**

* We use a Trie for university A to efficiently find all cases where a team $A_i$ is a proper prefix of another team $A_k$.
* We use a Trie on the reversed strings for university B to efficiently find all cases where a team $B_l$ is a proper suffix of another team $B_j$.
* Double polynomial string hashing is used to represent the extracted intermediate strings $S$ in $O(1)$ time.
* Sorting and two-pointer intersection (or binary search) are used to find common $S$ strings between the two universities to flag non-peculiar teams.

### Correctness argument

Let $S_A$ be the set of all non-empty strings $S$ such that $A_k = A_i + S$ for some $A_i, A_k \in A$.
Let $S_B$ be the set of all non-empty strings $S$ such that $B_j = S + B_l$ for some $B_l, B_j \in B$.
Any intersection $S \in S_A \cap S_B$ corresponds to at least one valid collision $A_i + B_j = A_k + B_l$. Because no two teams from the same university share the same name, an intersection strictly implies distinct teams. Every team participating in generating any $S \in S_A \cap S_B$ has at least one concatenation that can be replicated by another pair of teams, satisfying the definition of being non-peculiar. Marking all such teams and counting the unmarked ones guarantees we correctly count the number of peculiar teams in each university.

### Complexity analysis

* 
**Time Complexity:** $O(L_{total} + K \log K)$ where $L_{total} \le 10^6$ is the sum of the lengths of all strings in both sets, and $K$ is the number of valid prefix/suffix pairs found. Since each character of every string is visited at most once while descending the Trie, finding pairs takes $O(L_{total})$. Hashing is $O(1)$ per substring. The number of candidate strings $K$ is bounded by $L_{total}$, making the sorting step $O(K \log K)$. This comfortably executes within the 2.0 seconds time limit.


* **Memory/Space Complexity:** $O(L_{total} \times |\Sigma|)$ where $|\Sigma| [cite_start]= 26$. Tries allocate memory strictly bounded by the total number of characters. The hash states and lists of candidates scale linearly with $L_{total}$. Total memory consumption will be roughly 100-200 MB, safely within the generous 1024 MB limit.



### Complete C++20 implementation

```cpp
#include <iostream>
#include <vector>
#include <string>
#include <array>
#include <algorithm>
#include <chrono>
#include <random>

using namespace std;

const int M1 = 1e9 + 7;
const int M2 = 1e9 + 9;
int B1, B2;

vector<int> P1, P2;

void precompute(int max_len) {
    mt19937 rng(chrono::steady_clock::now().time_since_epoch().count());
    B1 = uniform_int_distribution<int>(300, 1e9 - 1)(rng);
    B2 = uniform_int_distribution<int>(300, 1e9 - 1)(rng);

    P1.assign(max_len + 1, 0);
    P2.assign(max_len + 1, 0);
    P1[0] = P2[0] = 1;
    for (int i = 1; i <= max_len; ++i) {
        P1[i] = (1LL * P1[i - 1] * B1) % M1;
        P2[i] = (1LL * P2[i - 1] * B2) % M2;
    }
}

struct StringHasher {
    vector<int> H1, H2;
    void init(const string& s) {
        int n = s.size();
        H1.assign(n + 1, 0);
        H2.assign(n + 1, 0);
        for (int i = 0; i < n; ++i) {
            H1[i + 1] = (1LL * H1[i] * B1 + s[i]) % M1;
            H2[i + 1] = (1LL * H2[i] * B2 + s[i]) % M2;
        }
    }
    pair<int, int> get_hash(int L, int R) const {
        if (L > R) return {0, 0};
        int len = R - L + 1;
        long long h1 = H1[R + 1] - 1LL * H1[L] * P1[len] % M1;
        if (h1 < 0) h1 += M1;
        long long h2 = H2[R + 1] - 1LL * H2[L] * P2[len] % M2;
        if (h2 < 0) h2 += M2;
        return {static_cast<int>(h1), static_cast<int>(h2)};
    }
};

struct Item {
    int len, h1, h2;
    bool operator<(const Item& o) const {
        if (len != o.len) return len < o.len;
        if (h1 != o.h1) return h1 < o.h1;
        return h2 < o.h2;
    }
    bool operator==(const Item& o) const {
        return len == o.len && h1 == o.h1 && h2 == o.h2;
    }
};

struct CollisionInfo {
    Item it;
    int id1, id2;
};

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(NULL);

    int M, N;
    if (!(cin >> M >> N)) return 0;

    vector<string> A(M);
    int max_len = 0;
    for (int i = 0; i < M; ++i) {
        cin >> A[i];
        max_len = max(max_len, (int)A[i].size());
    }

    vector<string> B(N);
    for (int i = 0; i < N; ++i) {
        cin >> B[i];
        max_len = max(max_len, (int)B[i].size());
    }

    precompute(max_len + 5);

    vector<StringHasher> hashA(M);
    for (int i = 0; i < M; ++i) hashA[i].init(A[i]);

    vector<StringHasher> hashB(N);
    for (int i = 0; i < N; ++i) hashB[i].init(B[i]);

    vector<array<int, 26>> trieA(1);
    trieA[0].fill(0);
    vector<int> endA(1, -1);

    for (int i = 0; i < M; ++i) {
        int u = 0;
        for (char c : A[i]) {
            int v = c - 'a';
            if (!trieA[u][v]) {
                trieA[u][v] = trieA.size();
                array<int, 26> empty_node;
                empty_node.fill(0);
                trieA.push_back(empty_node);
                endA.push_back(-1);
            }
            u = trieA[u][v];
        }
        endA[u] = i;
    }

    vector<CollisionInfo> ListA;
    for (int k = 0; k < M; ++k) {
        int u = 0;
        for (int i = 0; i < (int)A[k].size(); ++i) {
            if (endA[u] != -1) {
                int L = i;
                int R = A[k].size() - 1;
                pair<int, int> h = hashA[k].get_hash(L, R);
                ListA.push_back({{R - L + 1, h.first, h.second}, endA[u], k});
            }
            int v = A[k][i] - 'a';
            if (!trieA[u][v]) break;
            u = trieA[u][v];
        }
    }

    vector<array<int, 26>> trieB(1);
    trieB[0].fill(0);
    vector<int> endB(1, -1);

    for (int i = 0; i < N; ++i) {
        int u = 0;
        for (int j = (int)B[i].size() - 1; j >= 0; --j) {
            int v = B[i][j] - 'a';
            if (!trieB[u][v]) {
                trieB[u][v] = trieB.size();
                array<int, 26> empty_node;
                empty_node.fill(0);
                trieB.push_back(empty_node);
                endB.push_back(-1);
            }
            u = trieB[u][v];
        }
        endB[u] = i;
    }

    vector<CollisionInfo> ListB;
    for (int j = 0; j < N; ++j) {
        int u = 0;
        for (int i = 0; i < (int)B[j].size(); ++i) {
            if (endB[u] != -1) {
                int suf_len = i;
                int R = B[j].size() - suf_len - 1;
                int L = 0;
                pair<int, int> h = hashB[j].get_hash(L, R);
                ListB.push_back({{R - L + 1, h.first, h.second}, endB[u], j});
            }
            int v = B[j][B[j].size() - 1 - i] - 'a';
            if (!trieB[u][v]) break;
            u = trieB[u][v];
        }
    }

    vector<Item> hashesA, hashesB;
    for (const auto& x : ListA) hashesA.push_back(x.it);
    for (const auto& x : ListB) hashesB.push_back(x.it);

    sort(hashesA.begin(), hashesA.end());
    hashesA.erase(unique(hashesA.begin(), hashesA.end()), hashesA.end());

    sort(hashesB.begin(), hashesB.end());
    hashesB.erase(unique(hashesB.begin(), hashesB.end()), hashesB.end());

    vector<Item> common;
    set_intersection(hashesA.begin(), hashesA.end(),
                     hashesB.begin(), hashesB.end(),
                     back_inserter(common));

    vector<bool> badA(M, false);
    vector<bool> badB(N, false);

    for (const auto& x : ListA) {
        if (binary_search(common.begin(), common.end(), x.it)) {
            badA[x.id1] = true;
            badA[x.id2] = true;
        }
    }

    for (const auto& x : ListB) {
        if (binary_search(common.begin(), common.end(), x.it)) {
            badB[x.id1] = true;
            badB[x.id2] = true;
        }
    }

    int ansA = 0, ansB = 0;
    for (int i = 0; i < M; ++i) if (!badA[i]) ansA++;
    for (int i = 0; i < N; ++i) if (!badB[i]) ansB++;

    cout << ansA << " " << ansB << "\n";

    return 0;
}

