model solution output:
### Main idea

The problem asks us to find the number of valid multiset datasets (pairs of points) that lie on a single line and use exactly the given $N$ coordinates. A dataset is uniquely defined by its multiset of points.
Any dataset with $\ge 2$ distinct points lies on exactly one unique line. Datasets with exactly $1$ distinct point only lie on lines with a slope of $m = -1$ (i.e., $x+y=c$).
We can partition the counting into:

1. Lines with slope $m = -1$: For a dataset to lie on $x+y=c$, the sum of all coordinates must be $c \cdot N/2$. This uniquely fixes $c$. We can then independently match each coordinate $v$ with $c-v$, which allows us to find the number of ways to form points $(v, c-v)$.
2. All other lines ($m \neq -1$): For these lines, the chains of coordinate mappings $v \to m v + c$ do not form cycles (or only trivial ones). As a result, for any fixed line with $m \neq -1$, there is *at most one* valid dataset. We can identify all candidate lines by guessing the first point (which must include the minimum element of the array) and any second point. Then, for each unique valid candidate line, we greedily check if the remaining elements perfectly form points on it with $\ge 2$ distinct points to avoid double-counting.

### Technique used

Combinatorics for slope $m = -1$, and Backtracking / Constructive matching over a heuristically pruned set of candidate lines. Candidate generation takes $O(U^3)$ where $U$ is the number of unique elements, followed by $O(N \log N)$ matching.

### Correctness argument

For $m=-1$, the mapping is a simple involution: $x+y=c$. The number of datasets depends simply on the combinations of matching occurrences of $v$ and $c-v$.
For any slope $m \neq -1$, the recurrence $x \to mx + c$ ensures that directed mappings strictly increase or strictly decrease in absolute value, leaving no ambiguity (no branching) when greedily pairing the minimum unmatched coordinate. Hence, the coordinate partition is unique. Trying all pairs of points that could be formed by the pool of coordinates fully exhausts all candidate lines. Filtering datasets with $< 2$ distinct points correctly isolates the intersection between the two disjoint cases.

### Complexity analysis

* **Time Complexity:** $O(U^3 + C \cdot N \log N)$ where $U \le N \le 200$ is the number of unique coordinates, and $C$ is the number of geometrically unique candidate lines (typically very small, $\ll U^3$). In the worst case, generation takes $\approx 1.6 \times 10^7$ lightweight loops, easily passing the $2.0$ seconds limit. Overall Time Complexity: $\mathcal{O}(N^3)$.
* **Memory Complexity:** $\mathcal{O}(N^3)$ to temporarily store and deduplicate the parameters of the candidate lines.

### Complete C++20 implementation

```cpp
#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <map>
#include <set>

using namespace std;

const int MOD = 1000000007;

struct Line {
    long long A, B, C;
    bool operator<(const Line& o) const {
        if (A != o.A) return A < o.A;
        if (B != o.B) return B < o.B;
        return C < o.C;
    }
    bool operator==(const Line& o) const {
        return A == o.A && B == o.B && C == o.C;
    }
};

bool match(map<long long, int>& cnt, long long A, long long B, long long C, vector<pair<long long, long long>>& pts) {
    if (cnt.empty()) return true;
    auto it = cnt.begin();
    long long v = it->first;

    long long y_num = -A * v - C;
    if (y_num % B == 0) {
        long long y = y_num / B;
        if (cnt.count(y) && (y != v || cnt[v] >= 2)) {
            cnt[v]--; if (cnt[v] == 0) cnt.erase(v);
            cnt[y]--; if (cnt[y] == 0) cnt.erase(y);
            pts.push_back({v, y});
            if (match(cnt, A, B, C, pts)) return true;
            pts.pop_back();
            cnt[v]++; cnt[y]++;
        }
    }

    long long x_num = -B * v - C;
    if (x_num % A == 0) {
        long long x = x_num / A;
        if (cnt.count(x) && (x != v || cnt[v] >= 2)) {
            cnt[v]--; if (cnt[v] == 0) cnt.erase(v);
            cnt[x]--; if (cnt[x] == 0) cnt.erase(x);
            pts.push_back({x, v});
            if (match(cnt, A, B, C, pts)) return true;
            pts.pop_back();
            cnt[v]++; cnt[x]++;
        }
    }
    return false;
}

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(NULL);

    int N;
    if (!(cin >> N)) return 0;

    vector<long long> arr(N);
    long long sum_A = 0;
    map<long long, int> freq;
    for (int i = 0; i < N; ++i) {
        cin >> arr[i];
        sum_A += arr[i];
        freq[arr[i]]++;
    }

    sort(arr.begin(), arr.end());
    vector<long long> U_A;
    for (auto const& [val, count] : freq) {
        U_A.push_back(val);
    }

    long long ans1 = 0;
    if (sum_A % (N / 2) == 0) {
        long long c = sum_A / (N / 2);
        bool valid_c = true;
        long long ways = 1;
        for (auto const& [v, f] : freq) {
            long long target = c - v;
            if (v < target) {
                if (freq.count(target) && freq[target] == f) {
                    ways = (ways * (f + 1)) % MOD;
                } else {
                    valid_c = false;
                    break;
                }
            } else if (v == target) {
                if (f % 2 != 0) {
                    valid_c = false;
                    break;
                }
            }
        }
        if (valid_c) {
            ans1 = ways;
        }
    }

    long long ans2 = 0;
    for (long long u : U_A) {
        if (freq[u] >= N / 2) {
            int unique_rem = 0;
            for (auto const& [v, f] : freq) {
                int rem_f = f - (v == u ? N / 2 : 0);
                if (rem_f > 0) unique_rem++;
            }
            if (unique_rem >= 2) {
                ans2 = (ans2 + 2) % MOD; 
            }
        }
    }

    vector<Line> candidates;
    long long a0 = arr[0];
    for (long long u1 : U_A) {
        for (int swap1 = 0; swap1 < 2; ++swap1) {
            long long x1 = swap1 ? u1 : a0;
            long long y1 = swap1 ? a0 : u1;
            for (long long x2 : U_A) {
                for (long long y2 : U_A) {
                    if (x1 == x2 && y1 == y2) continue;
                    long long dy = y2 - y1;
                    long long dx = x2 - x1;
                    long long g = std::gcd(std::abs(dy), std::abs(dx));
                    dy /= g; dx /= g;
                    if (dy < 0 || (dy == 0 && dx < 0)) {
                        dy = -dy; dx = -dx;
                    }
                    long long A = dy, B = -dx;
                    long long C = -(A * x1 + B * y1);

                    if (A == 0 || B == 0) continue;
                    if (A == B) continue;

                    candidates.push_back({A, B, C});
                }
            }
        }
    }

    sort(candidates.begin(), candidates.end());
    candidates.erase(unique(candidates.begin(), candidates.end()), candidates.end());

    for (const Line& L : candidates) {
        map<long long, int> cnt = freq;
        vector<pair<long long, long long>> pts;
        if (match(cnt, L.A, L.B, L.C, pts)) {
            sort(pts.begin(), pts.end());
            pts.erase(unique(pts.begin(), pts.end()), pts.end());
            if (pts.size() >= 2) {
                ans2 = (ans2 + 1) % MOD;
            }
        }
    }

    cout << (ans1 + ans2) % MOD << "\n";
    return 0;
}

